@api_router.get("/followups/today")
async def get_todays_followups(user = Depends(get_current_user)):
    """Get all follow-ups due today for the current user"""
    today = datetime.now(timezone.utc).replace(hour=0, minute=0, second=0, microsecond=0)
    today_end = today.replace(hour=23, minute=59, second=59)
    today_str = today.strftime("%Y-%m-%d")
    
    # Query for leads with either reminder_date OR follow_up_date today
    # reminder_date is stored as string "YYYY-MM-DD", follow_up_date is datetime
    query_base = {
        "$or": [
            {"reminder_date": today_str, "reminder_completed": {"$ne": True}},
            {"follow_up_date": {"$gte": today, "$lte": today_end}}
        ]
    }
    
    # Filter by user role
    if user["role"] == "sales_executive":
        lead_query = {**query_base, "assigned_to": user["id"]}
    elif user["role"] in ["cs_agent", "cs_head"]:
        lead_query = {**query_base}  # CS doesn't have leads
    elif user["role"] in ["mentor", "academic_master", "master_of_academics", "master_of_academics_"]:
        lead_query = {**query_base}  # Mentors don't have leads
    else:
        lead_query = query_base
    
    # Get leads with reminders
    leads = []
    if user["role"] not in ["cs_agent", "cs_head", "mentor", "academic_master", "master_of_academics", "master_of_academics_"]:
        if user["role"] == "sales_executive":
            leads = await db.leads.find({**query_base, "assigned_to": user["id"]}, {"_id": 0}).to_list(1000)
        else:
            leads = await db.leads.find(query_base, {"_id": 0}).to_list(1000)
    
    # Get students with reminders (CS for upgrades, Mentors for redeposits)
    student_query_base = {
        "$or": [
            {"reminder_date": today_str, "reminder_completed": {"$ne": True}},
            {"follow_up_date": {"$gte": today, "$lte": today_end}}
        ]
    }
    students = []
    if user["role"] in ["cs_agent", "cs_head"]:
        if user["role"] == "cs_agent":
            students = await db.students.find({**student_query_base, "cs_agent_id": user["id"]}, {"_id": 0}).to_list(1000)
        else:
            students = await db.students.find(student_query_base, {"_id": 0}).to_list(1000)
    elif user["role"] in ["mentor", "academic_master", "master_of_academics", "master_of_academics_"]:
        if user["role"] == "mentor":
            students = await db.students.find({**student_query_base, "mentor_id": user["id"]}, {"_id": 0}).to_list(1000)
        else:
            students = await db.students.find(student_query_base, {"_id": 0}).to_list(1000)
    elif user["role"] in ["super_admin", "admin"]:
        students = await db.students.find(student_query_base, {"_id": 0}).to_list(1000)
    
    # Categorize by time
    def get_time_slot(time_val):
        if not time_val:
            return "unscheduled"
        try:
            # Handle datetime objects
            if hasattr(time_val, 'hour'):
                hour = time_val.hour
            # Handle string formats
            elif isinstance(time_val, str):
                if "T" in time_val:
                    time_val = time_val.split("T")[1][:5]
                elif " " in time_val:
                    time_val = time_val.split(" ")[1][:5]
                hour = int(time_val.split(":")[0])
            else:
                return "unscheduled"
            
            if hour < 12:
                return "morning"
            elif hour < 17:
                return "afternoon"
            else:
                return "evening"
        except:
            return "unscheduled"
    
    # Group follow-ups
    followups = {
        "morning": [],
        "afternoon": [],
        "evening": [],
        "unscheduled": []
    }
    
    for lead in leads:
        lead["entity_type"] = "lead"
        lead["reminder_type"] = "sales"
        # Use follow_up_date if reminder_time not set
        time_val = lead.get("reminder_time") or lead.get("follow_up_date")
        slot = get_time_slot(time_val)
        followups[slot].append(lead)
    
    for student in students:
        student["entity_type"] = "student"
        time_val = student.get("reminder_time") or student.get("follow_up_date")
        slot = get_time_slot(time_val)
        followups[slot].append(student)
    
    # Sort each slot by time
    def get_sort_key(x):
        rt = x.get("reminder_time")
        fud = x.get("follow_up_date")
        if rt:
            return rt
        if fud:
            if hasattr(fud, 'strftime'):
                return fud.strftime("%H:%M")
            return str(fud)
        return "99:99"
    
    for slot in followups:
        followups[slot].sort(key=get_sort_key)
    
    total = len(leads) + len(students)
    
    return {
        "date": today_str,
        "total_followups": total,
        "followups": followups,
        "leads_count": len(leads),
        "students_count": len(students)
    }

@api_router.get("/followups/upcoming")
async def get_upcoming_followups(days: int = 7, user = Depends(get_current_user)):
    """Get follow-ups for the next N days"""
    today = datetime.now(timezone.utc)
    end_date = (today + timedelta(days=days)).strftime("%Y-%m-%d")
    today_str = today.strftime("%Y-%m-%d")
    
    query_base = {
        "reminder_date": {"$gte": today_str, "$lte": end_date},
        "reminder_completed": {"$ne": True}
    }
    
    # Get leads
    leads = []
    if user["role"] == "sales_executive":
        leads = await db.leads.find({**query_base, "assigned_to": user["id"]}, {"_id": 0}).to_list(1000)
    elif user["role"] not in ["cs_agent", "cs_head", "mentor", "academic_master", "master_of_academics", "master_of_academics_"]:
        leads = await db.leads.find(query_base, {"_id": 0}).to_list(1000)
    
    # Get students
    students = []
    if user["role"] == "cs_agent":
        students = await db.students.find({**query_base, "cs_agent_id": user["id"]}, {"_id": 0}).to_list(1000)
    elif user["role"] == "mentor":
        students = await db.students.find({**query_base, "mentor_id": user["id"]}, {"_id": 0}).to_list(1000)
    elif user["role"] in ["super_admin", "admin", "cs_head", "academic_master", "master_of_academics", "master_of_academics_"]:
        students = await db.students.find(query_base, {"_id": 0}).to_list(1000)
    
    # Group by date
    by_date = {}
    
    for lead in leads:
        lead["entity_type"] = "lead"
        lead["reminder_type"] = "sales"
        date = lead.get("reminder_date", today_str)
        if date not in by_date:
            by_date[date] = []
        by_date[date].append(lead)
    
    for student in students:
        student["entity_type"] = "student"
        date = student.get("reminder_date", today_str)
        if date not in by_date:
            by_date[date] = []
        by_date[date].append(student)
    
    return {
        "days": days,
        "total": len(leads) + len(students),
        "by_date": by_date
    }

# ==================== CUSTOMER MASTER ====================

@api_router.get("/customers")
async def get_customers(
    search: Optional[str] = None,
    limit: int = 2000,
    sort_by: str = "created_at",
    sort_order: str = "asc",
    user = Depends(get_current_user)
):
    """Get all customers with transaction history, sortable by total_spent or date"""
    query = {}
    if search:
        query["$or"] = [
            {"full_name": {"$regex": search, "$options": "i"}},
            {"phone": {"$regex": search, "$options": "i"}},
            {"email": {"$regex": search, "$options": "i"}}
        ]
    
    # Validate sort_by field
    allowed_sort_fields = ["created_at", "total_spent", "full_name", "transaction_count", "net_ltv"]
    if sort_by not in allowed_sort_fields:
        sort_by = "created_at"
    
    # If sorting by net_ltv, sort in Python after enrichment
    if sort_by == "net_ltv":
        db_sort_by = "total_spent"
    else:
        db_sort_by = sort_by
    
    sort_dir = 1 if sort_order == "asc" else -1
    customers = await db.customers.find(query, {"_id": 0}).sort(db_sort_by, sort_dir).to_list(limit)
    
    # Enrich customers with mentor deposit/withdrawal totals for LTV
    student_ids = [c.get("student_id") for c in customers if c.get("student_id")]
    if student_ids:
        dep_agg = await db.mentor_redeposits.aggregate([
            {"$match": {"student_id": {"$in": student_ids}}},
            {"$group": {"_id": "$student_id", "total_dep": {"$sum": {"$ifNull": ["$amount_aed", "$amount"]}}}}
        ]).to_list(2000)
        wd_agg = await db.mentor_withdrawals.aggregate([
            {"$match": {"student_id": {"$in": student_ids}}},
            {"$group": {"_id": "$student_id", "total_wd": {"$sum": {"$ifNull": ["$amount_aed", "$amount"]}}}}
        ]).to_list(2000)
        dep_map = {d["_id"]: d["total_dep"] for d in dep_agg}
        wd_map = {w["_id"]: w["total_wd"] for w in wd_agg}
        
        for c in customers:
            sid = c.get("student_id")
            if sid:
                dep_total = dep_map.get(sid, 0)
                wd_total = wd_map.get(sid, 0)
                c["mentor_deposits_total"] = round(dep_total, 2)
                c["mentor_withdrawals_total"] = round(wd_total, 2)
                c["net_ltv"] = round((c.get("total_spent", 0) + dep_total - wd_total), 2)
            else:
                c["net_ltv"] = c.get("total_spent", 0)
    
    # Sort by net_ltv in Python after enrichment
    if sort_by == "net_ltv":
        customers.sort(key=lambda x: x.get("net_ltv", 0), reverse=(sort_order == "desc"))
    
    return customers

@api_router.get("/customers/{customer_id}")
async def get_customer(customer_id: str, user = Depends(get_current_user)):
    """Get a single customer with full transaction history"""
    customer = await db.customers.find_one({"id": customer_id}, {"_id": 0})
    if not customer:
        raise HTTPException(status_code=404, detail="Customer not found")
    
    # Enrich transaction data with course names
    if customer.get("transactions"):
        for txn in customer["transactions"]:
            if txn.get("course_id"):
                course = await db.courses.find_one({"id": txn["course_id"]})
                txn["course_name"] = course.get("name") if course else None
    
    # Get associated lead and student info
    if customer.get("lead_id"):
        lead = await db.leads.find_one({"id": customer["lead_id"]}, {"_id": 0})
        customer["lead_info"] = lead
    
    if customer.get("student_id"):
        student = await db.students.find_one({"id": customer["student_id"]}, {"_id": 0})
        customer["student_info"] = student
        
        # Include mentor deposits and withdrawals for this student
        mentor_deposits = await db.mentor_redeposits.find(
            {"student_id": customer["student_id"]}, {"_id": 0, "date": 1, "amount": 1, "amount_aed": 1, "mentor_name": 1, "month": 1}
        ).sort("date", -1).to_list(100)
        
        mentor_withdrawals = await db.mentor_withdrawals.find(
            {"student_id": customer["student_id"]}, {"_id": 0, "date": 1, "amount": 1, "amount_aed": 1, "mentor_name": 1, "month": 1}
        ).sort("date", -1).to_list(100)
        
        total_deposits_aed = sum(d.get("amount_aed") or d.get("amount", 0) for d in mentor_deposits)
        total_withdrawals_aed = sum(w.get("amount_aed") or w.get("amount", 0) for w in mentor_withdrawals)
        
        customer["mentor_deposits"] = [{"date": d.get("date"), "amount_aed": round(d.get("amount_aed") or d.get("amount", 0), 2), "mentor_name": d.get("mentor_name"), "type": "deposit"} for d in mentor_deposits]
        customer["mentor_withdrawals"] = [{"date": w.get("date"), "amount_aed": round(w.get("amount_aed") or w.get("amount", 0), 2), "mentor_name": w.get("mentor_name"), "type": "withdrawal"} for w in mentor_withdrawals]
        customer["mentor_totals"] = {
            "total_deposits_aed": round(total_deposits_aed, 2),
            "total_withdrawals_aed": round(total_withdrawals_aed, 2),
            "net_mentor_value": round(total_deposits_aed - total_withdrawals_aed, 2),
        }
        # Net LTV = enrollment spend + net mentor value
        enrollment_spent = customer.get("total_spent", 0)
        customer["net_ltv"] = round(enrollment_spent + total_deposits_aed - total_withdrawals_aed, 2)
    
    return customer

