# ==================== MENTOR DASHBOARD ====================

@api_router.get("/mentor/dashboard")
async def get_mentor_dashboard(
    period: str = "overall",
    view_mode: Optional[str] = None,
    user = Depends(get_current_user)
):
    """Enhanced mentor dashboard with role-based views, commissions, and bonus slabs."""
    USD_TO_AED = float(os.environ.get("USD_TO_AED_RATE", "3.674"))
    role = user.get("role")
    is_master = role in ("master_of_academics", "master_of_academics_")
    is_admin = role in ["super_admin", "admin"]

    if role not in ["mentor", "master_of_academics", "master_of_academics_", "super_admin", "admin"]:
        raise HTTPException(status_code=403, detail="Access denied")

    # Determine effective view
    if is_admin or is_master:
        effective_view = view_mode or "team"
    else:
        effective_view = "individual"

    # Build mentor filter
    if effective_view == "individual" and not is_admin:
        mentor_ids = [user["id"]]
    elif is_master and effective_view == "team":
        team_mentors = await db.users.find(
            {"role": {"$in": ["mentor", "master_of_academics", "master_of_academics_"]}, "team_id": user.get("team_id")},
            {"_id": 0, "id": 1}
        ).to_list(100)
        mentor_ids = [m["id"] for m in team_mentors] if team_mentors else [user["id"]]
    else:
        mentor_ids = None  # all mentors

    # Date filter
    date_start, date_end = _get_date_range(period)
    date_q = {}
    if date_start:
        date_q["date"] = {"$gte": date_start}
        if date_end:
            date_q["date"]["$lt"] = date_end

    # ---------- DEPOSITS ----------
    dep_match = {**date_q}
    if mentor_ids:
        dep_match["mentor_id"] = {"$in": mentor_ids}
    deposits = await db.mentor_redeposits.find(dep_match, {"_id": 0}).to_list(50000)
    total_deposits_usd = sum(d.get("amount", 0) for d in deposits)
    total_deposits_aed = round(total_deposits_usd * USD_TO_AED, 2)

    # ---------- WITHDRAWALS ----------
    wd_match = {**date_q}
    if mentor_ids:
        wd_match["mentor_id"] = {"$in": mentor_ids}
    withdrawals = await db.mentor_withdrawals.find(wd_match, {"_id": 0}).to_list(50000)
    total_withdrawals_usd = sum(w.get("amount", 0) for w in withdrawals)
    total_withdrawals_aed = round(total_withdrawals_usd * USD_TO_AED, 2)

    net_usd = total_deposits_usd - total_withdrawals_usd
    net_aed = round(net_usd * USD_TO_AED, 2)

    # ---------- STUDENTS ----------
    student_q = {}
    if mentor_ids:
        student_q["mentor_id"] = {"$in": mentor_ids}
    students = await db.students.find(student_q, {"_id": 0, "id": 1, "mentor_stage": 1, "full_name": 1}).to_list(50000)
    total_students = len(students)
    student_stages = {}
    for s in students:
        stage = s.get("mentor_stage", "new_student")
        student_stages[stage] = student_stages.get(stage, 0) + 1
    students_connected = sum(1 for s in students if s.get("mentor_stage") != "new_student")

    # ---------- COMMISSIONS ----------
    # Flat commission = 1% of each deposit in AED
    flat_commission_aed = round(total_deposits_aed * 0.01, 2)
    # Net commission = 1% of net (deposits - withdrawals) in AED
    net_commission_rate = 0.01  # All mentors (including Edwin) get 1% net commission
    net_commission_aed = round(net_aed * net_commission_rate, 2)

    # Edwin's team override (0.5% on entire team net)
    team_override_aed = 0
    if is_master:
        all_team_dep_q = {**date_q}
        team_m = await db.users.find({"role": {"$in": ["mentor", "master_of_academics", "master_of_academics_"]}, "team_id": user.get("team_id")}, {"_id": 0, "id": 1}).to_list(100)
        all_team_ids = [m["id"] for m in team_m]
        if all_team_ids:
            all_team_dep_q["mentor_id"] = {"$in": all_team_ids}
        all_team_deposits_usd = 0
        all_team_withdrawals_usd = 0
        async for d in db.mentor_redeposits.find(all_team_dep_q, {"_id": 0, "amount": 1}):
            all_team_deposits_usd += d.get("amount", 0)
        wd_q2 = {**date_q}
        if all_team_ids:
            wd_q2["mentor_id"] = {"$in": all_team_ids}
        async for w in db.mentor_withdrawals.find(wd_q2, {"_id": 0, "amount": 1}):
            all_team_withdrawals_usd += w.get("amount", 0)
        team_net_usd = all_team_deposits_usd - all_team_withdrawals_usd
        team_override_aed = round(team_net_usd * USD_TO_AED * 0.005, 2)

    total_commission_aed = flat_commission_aed + net_commission_aed + team_override_aed

    # ---------- BONUS SLAB (Effort-Based) ----------
    # Bonus is based on total "effort" — all deposits the mentor brought in
    # (own students + cross-mentor deposits they secured for others)
    now = datetime.now(timezone.utc)
    month_start = now.replace(day=1).isoformat()[:10]
    bonus_wd_q = {"date": {"$gte": month_start}}

    if effective_view == "individual" and not is_admin:
        uid = user["id"]
        # Effort-based: own deposits (no effort_by or effort_by=self) + cross deposits they secured
        bonus_dep_q = {"date": {"$gte": month_start}, "$or": [
            {"effort_by_id": uid},
            {"mentor_id": uid, "effort_by_id": {"$in": [None]}},
            {"mentor_id": uid, "effort_by_id": {"$exists": False}},
        ]}
        bonus_wd_q["mentor_id"] = uid
    elif mentor_ids:
        bonus_dep_q = {"date": {"$gte": month_start}, "$or": [
            {"effort_by_id": {"$in": mentor_ids}},
            {"mentor_id": {"$in": mentor_ids}, "effort_by_id": {"$in": [None]}},
            {"mentor_id": {"$in": mentor_ids}, "effort_by_id": {"$exists": False}},
        ]}
        bonus_wd_q["mentor_id"] = {"$in": mentor_ids}
    else:
        bonus_dep_q = {"date": {"$gte": month_start}}

    month_deposits_usd = 0
    async for d in db.mentor_redeposits.find(bonus_dep_q, {"_id": 0, "amount": 1}):
        month_deposits_usd += d.get("amount", 0)
    month_withdrawals_usd = 0
    async for w in db.mentor_withdrawals.find(bonus_wd_q, {"_id": 0, "amount": 1}):
        month_withdrawals_usd += w.get("amount", 0)
    month_net_usd = month_deposits_usd - month_withdrawals_usd

    slabs = [
        {"threshold": 10000, "bonus_pct": 10},
        {"threshold": 20000, "bonus_pct": 15},
        {"threshold": 30000, "bonus_pct": 17.5},
        {"threshold": 40000, "bonus_pct": 20},
        {"threshold": 50000, "bonus_pct": 25},
    ]
    current_slab = None
    next_slab = None
    for i, slab in enumerate(slabs):
        if month_net_usd >= slab["threshold"]:
            current_slab = slab
            next_slab = slabs[i+1] if i+1 < len(slabs) else None
        else:
            next_slab = slab
            break

    # Get salary for bonus calculation
    # For individual mentor: use their salary
    # For team/admin view: aggregate per-mentor bonuses
    salary_aed = 0
    bonus_amount_aed = 0

    if effective_view == "individual" and not is_admin:
        # Single mentor — use their salary
        hr_emp = await db.hr_employees.find_one({"user_id": user["id"]}, {"_id": 0, "salary_structure": 1, "salary": 1})
        salary_aed = _get_employee_salary_aed(hr_emp)
        bonus_amount_aed = round(salary_aed * (current_slab["bonus_pct"] / 100), 2) if current_slab else 0
    else:
        # Team/admin view: calculate each mentor's individual bonus and sum
        bonus_mentor_ids = mentor_ids or [m["id"] async for m in db.users.find({"role": {"$in": ["mentor", "master_of_academics", "master_of_academics_"]}}, {"_id": 0, "id": 1})]
        total_salary = 0
        total_bonus = 0
        for mid in bonus_mentor_ids:
            # Effort-based: own deposits + cross deposits they secured
            m_dep_q = {"date": {"$gte": month_start}, "$or": [
                {"effort_by_id": mid},
                {"mentor_id": mid, "effort_by_id": {"$in": [None]}},
                {"mentor_id": mid, "effort_by_id": {"$exists": False}},
            ]}
            m_wd_q = {"date": {"$gte": month_start}, "mentor_id": mid}
            m_dep = sum([d.get("amount", 0) async for d in db.mentor_redeposits.find(m_dep_q, {"_id": 0, "amount": 1})])
            m_wd = sum([w.get("amount", 0) async for w in db.mentor_withdrawals.find(m_wd_q, {"_id": 0, "amount": 1})])
            m_net = m_dep - m_wd

            # Find this mentor's slab
            m_slab = None
            for slab in slabs:
                if m_net >= slab["threshold"]:
                    m_slab = slab

            # Get this mentor's salary
            hr_emp = await db.hr_employees.find_one({"user_id": mid}, {"_id": 0, "salary_structure": 1, "salary": 1})
            m_salary = _get_employee_salary_aed(hr_emp)

            total_salary += m_salary
            if m_slab:
                total_bonus += round(m_salary * (m_slab["bonus_pct"] / 100), 2)

        salary_aed = total_salary
        bonus_amount_aed = total_bonus

    return {
        "total_students": total_students,
        "students_connected": students_connected,
        "students_balance": total_students - students_connected,
        "student_stages": student_stages,
        "total_deposits_usd": total_deposits_usd,
        "total_deposits_aed": total_deposits_aed,
        "total_withdrawals_usd": total_withdrawals_usd,
        "total_withdrawals_aed": total_withdrawals_aed,
        "net_usd": net_usd,
        "net_aed": net_aed,
        "flat_commission_aed": flat_commission_aed,
        "net_commission_aed": net_commission_aed,
        "team_override_aed": team_override_aed,
        "total_commission_aed": total_commission_aed,
        "is_master": is_master,
        "effective_view": effective_view,
        "bonus": {
            "month_net_usd": month_net_usd,
            "current_slab": current_slab,
            "next_slab": next_slab,
            "salary_aed": salary_aed,
            "bonus_amount_aed": bonus_amount_aed,
            "slabs": slabs,
        },
    }


@api_router.get("/mentor/dashboard/monthly-trend")
async def get_mentor_monthly_trend(view_mode: str = "individual", user=Depends(get_current_user)):
    """Monthly deposit/withdrawal trend for mentors."""
    USD_TO_AED = float(os.environ.get("USD_TO_AED_RATE", "3.674"))
    role = user.get("role")
    is_master = role in ("master_of_academics", "master_of_academics_")
    is_admin = role in ["super_admin", "admin"]

    if role not in ["mentor", "master_of_academics", "master_of_academics_", "super_admin", "admin"]:
        raise HTTPException(status_code=403, detail="Access denied")

    mentor_filter = {}
    if view_mode == "individual" and not is_admin:
        mentor_filter = {"mentor_id": user["id"]}
    elif is_master and view_mode == "team":
        tm = await db.users.find({"role": {"$in": ["mentor", "master_of_academics", "master_of_academics_"]}, "team_id": user.get("team_id")}, {"_id": 0, "id": 1}).to_list(100)
        mentor_filter = {"mentor_id": {"$in": [m["id"] for m in tm]}} if tm else {"mentor_id": user["id"]}

    dep_pipeline = [
        {"$match": mentor_filter},
        {"$group": {"_id": {"$substr": ["$date", 0, 7]}, "deposits": {"$sum": "$amount"}, "count": {"$sum": 1}}},
        {"$sort": {"_id": 1}},
    ]
    wd_pipeline = [
        {"$match": mentor_filter},
        {"$group": {"_id": {"$substr": ["$date", 0, 7]}, "withdrawals": {"$sum": "$amount"}}},
    ]
    dep_data = {d["_id"]: d for d in await db.mentor_redeposits.aggregate(dep_pipeline).to_list(100)}
    wd_data = {w["_id"]: w for w in await db.mentor_withdrawals.aggregate(wd_pipeline).to_list(100)}
    all_months = sorted(set(list(dep_data.keys()) + list(wd_data.keys())))

    result = []
    for m in all_months:
        dep_usd = dep_data.get(m, {}).get("deposits", 0)
        wd_usd = wd_data.get(m, {}).get("withdrawals", 0)
        result.append({
            "month": m,
            "deposits_usd": dep_usd, "deposits_aed": round(dep_usd * USD_TO_AED, 2),
            "withdrawals_usd": wd_usd, "withdrawals_aed": round(wd_usd * USD_TO_AED, 2),
            "net_usd": dep_usd - wd_usd, "net_aed": round((dep_usd - wd_usd) * USD_TO_AED, 2),
            "deposit_count": dep_data.get(m, {}).get("count", 0),
        })
    return result


@api_router.get("/mentor/dashboard/leaderboard")
async def get_mentor_leaderboard_v2(period: str = "overall", user=Depends(get_current_user)):
    """Mentor leaderboard by net deposits."""
    USD_TO_AED = float(os.environ.get("USD_TO_AED_RATE", "3.674"))
    date_start, date_end = _get_date_range(period)
    date_q = {}
    if date_start:
        date_q["date"] = {"$gte": date_start}
        if date_end:
            date_q["date"]["$lt"] = date_end

    dep_pipeline = [
        {"$match": date_q},
        {"$group": {"_id": "$mentor_id", "name": {"$first": "$mentor_name"}, "deposits": {"$sum": "$amount"}, "count": {"$sum": 1}}},
    ]
    wd_pipeline = [
        {"$match": date_q},
        {"$group": {"_id": "$mentor_id", "withdrawals": {"$sum": "$amount"}}},
    ]
    dep_map = {d["_id"]: d for d in await db.mentor_redeposits.aggregate(dep_pipeline).to_list(100)}
    wd_map = {w["_id"]: w for w in await db.mentor_withdrawals.aggregate(wd_pipeline).to_list(100)}

    all_ids = set(list(dep_map.keys()) + list(wd_map.keys()))
    board = []
    for mid in all_ids:
        dep = dep_map.get(mid, {})
        wd = wd_map.get(mid, {})
        dep_usd = dep.get("deposits", 0)
        wd_usd = wd.get("withdrawals", 0)
        board.append({
            "mentor_id": mid,
            "mentor_name": dep.get("name") or wd.get("name", "Unknown"),
            "deposits_usd": dep_usd,
            "deposits_aed": round(dep_usd * USD_TO_AED, 2),
            "withdrawals_usd": wd_usd,
            "net_usd": dep_usd - wd_usd,
            "net_aed": round((dep_usd - wd_usd) * USD_TO_AED, 2),
            "deposit_count": dep.get("count", 0),
        })
    board.sort(key=lambda x: x["net_usd"], reverse=True)
    return board


# ─── Cross-Mentor Deposits ───────────────────────────────────────────────
BONUS_TIERS = [
    {"min_usd": 50000, "pct": 25},
    {"min_usd": 40000, "pct": 20},
    {"min_usd": 30000, "pct": 17.5},
    {"min_usd": 20000, "pct": 15},
    {"min_usd": 10000, "pct": 10},
]

def _get_bonus_tier(total_effort_usd: float):
    for t in BONUS_TIERS:
        if total_effort_usd >= t["min_usd"]:
            return t
    return None


def _get_employee_salary_aed(hr_emp: dict) -> float:
    """Consistent salary lookup from hr_employees record.
    Priority: top-level 'salary' (HR-entered truth) > computed from structure components > structure gross/net.
    """
    if not hr_emp:
        return 0
    # 1. Top-level salary field — most reliable, manually set by HR
    top_salary = hr_emp.get("salary")
    if top_salary and float(top_salary) > 0:
        return float(top_salary)
    # 2. Compute from salary_structure components
    ss = hr_emp.get("salary_structure") or {}
    computed = sum(float(ss.get(k, 0) or 0) for k in [
        "basic_salary", "housing_allowance", "transport_allowance",
        "food_allowance", "phone_allowance", "other_allowances", "fixed_incentive"
    ])
    if computed > 0:
        return computed
    # 3. Fallback to stored gross/net in structure
    return float(ss.get("gross_salary") or ss.get("net_salary") or 0)

@api_router.get("/mentor/cross-deposits")
async def get_cross_mentor_deposits(
    period: str = "this_month",
    custom_start: Optional[str] = None,
    custom_end: Optional[str] = None,
    user=Depends(get_current_user),
):
    """List cross-mentor deposits — deposits recorded by mentors for OTHER mentors' students."""
    role = user["role"]
    if role not in ["mentor", "master_of_academics", "master_of_academics_", "super_admin", "admin"]:
        raise HTTPException(status_code=403, detail="Access denied")

    USD_TO_AED = float(os.environ.get("USD_TO_AED_RATE", "3.674"))
    date_start, date_end = _get_date_range(period, custom_start, custom_end)

    query = {"effort_by_id": {"$exists": True, "$ne": None}}
    if date_start:
        query["date"] = {"$gte": date_start}
        if date_end:
            query["date"]["$lt"] = date_end
    if role in ["mentor", "master_of_academics", "master_of_academics_"] and role not in ["super_admin", "admin"]:
        query["effort_by_id"] = user["id"]

    deposits = await db.mentor_redeposits.find(query, {"_id": 0}).sort("date", -1).to_list(500)

    # Calculate effort summary by mentor
    effort_pipeline = [
        {"$match": query},
        {"$group": {"_id": "$effort_by_id", "name": {"$first": "$effort_by_name"}, "total_usd": {"$sum": "$amount"}, "count": {"$sum": 1}}},
        {"$sort": {"total_usd": -1}},
    ]
    effort_summary = await db.mentor_redeposits.aggregate(effort_pipeline).to_list(50)

    return {
        "deposits": [{**d, "amount_aed": round(d.get("amount", 0) * USD_TO_AED, 2)} for d in deposits],
        "effort_summary": [
            {
                "mentor_id": e["_id"],
                "mentor_name": e.get("name", "Unknown"),
                "total_effort_usd": e["total_usd"],
                "total_effort_aed": round(e["total_usd"] * USD_TO_AED, 2),
                "deposit_count": e["count"],
                "bonus_tier": _get_bonus_tier(e["total_usd"]),
            }
            for e in effort_summary
        ],
    }


@api_router.get("/mentor/cross-deposits/search-student")
async def search_student_for_cross_deposit(q: str, user=Depends(get_current_user)):
    """Search students by name/email/phone for cross-deposit recording."""
    if not q or len(q) < 2:
        return []
    regex = {"$regex": q, "$options": "i"}
    students = await db.students.find(
        {"$or": [{"full_name": regex}, {"email": regex}, {"phone": regex}]},
        {"_id": 0, "id": 1, "full_name": 1, "email": 1, "phone": 1, "mt5_id": 1,
         "mentor_id": 1, "mentor_name": 1, "bd_agent_id": 1, "bd_agent_name": 1,
         "cs_agent_id": 1, "cs_agent_name": 1}
    ).limit(10).to_list(10)
    return students


@api_router.post("/mentor/cross-deposits")
async def record_cross_mentor_deposit(data: dict = Body(...), user=Depends(get_current_user)):
    """Record a deposit brought by a mentor for another mentor's student.
    The effort_by is the mentor who convinced the student. The mentor_id is the assigned mentor.
    """
    role = user["role"]
    if role not in ["mentor", "master_of_academics", "master_of_academics_", "super_admin", "admin"]:
        raise HTTPException(status_code=403, detail="Access denied")

    student_id = data.get("student_id")
    amount = float(data.get("amount", 0))
    if not student_id or amount <= 0:
        raise HTTPException(status_code=400, detail="student_id and positive amount required")

    student = await db.students.find_one({"id": student_id}, {"_id": 0})
    if not student:
        raise HTTPException(status_code=404, detail="Student not found")

    USD_TO_AED = float(os.environ.get("USD_TO_AED_RATE", "3.674"))
    now = datetime.now(timezone.utc)
    month = now.strftime("%Y-%m")

    deposit_record = {
        "id": str(uuid.uuid4()),
        "month": data.get("month", month),
        "date": data.get("date", now.strftime("%Y-%m-%d")),
        "mentor_id": student.get("mentor_id"),
        "mentor_name": student.get("mentor_name"),
        "student_id": student_id,
        "student_name": student.get("full_name"),
        "student_email": student.get("email"),
        "amount": amount,
        "amount_aed": round(amount * USD_TO_AED, 2),
        "status": "closed",
        "effort_by_id": user["id"],
        "effort_by_name": user.get("full_name"),
        "notes": data.get("notes", ""),
        "screenshot_url": data.get("screenshot_url"),
        "created_at": now.isoformat(),
        "created_by": user["id"],
    }

    await db.mentor_redeposits.insert_one(deposit_record)

    # Also update customer master
    customer = await db.customers.find_one({"phone": student.get("phone")})
    if customer:
        txn = {
            "payment_id": deposit_record["id"],
            "amount": round(amount * USD_TO_AED, 2),
            "currency": "AED",
            "payment_method": "mentor_redeposit",
            "payment_type": "cross_mentor_deposit",
            "course_name": f"Cross-deposit (effort: {user.get('full_name')})",
            "date": deposit_record["date"],
        }
        await db.customers.update_one(
            {"id": customer["id"]},
            {"$push": {"transactions": txn}, "$inc": {"total_spent": txn["amount"], "transaction_count": 1},
             "$set": {"updated_at": now.isoformat()}}
        )

    # Send notification to the assigned mentor
    if student.get("mentor_id") and student["mentor_id"] != user["id"]:
        await db.notifications.insert_one({
            "id": str(uuid.uuid4()),
            "user_id": student["mentor_id"],
            "type": "cross_deposit",
            "title": "Cross-Mentor Deposit Recorded",
            "message": f"{user.get('full_name')} recorded a ${amount} deposit for your student {student.get('full_name')}",
            "read": False,
            "created_at": now.isoformat(),
        })

    deposit_record.pop("_id", None)
    return deposit_record


@api_router.get("/mentor/effort-summary")
async def get_mentor_effort_summary(
    period: str = "this_month",
    custom_start: Optional[str] = None,
    custom_end: Optional[str] = None,
    user=Depends(get_current_user),
):
    """Get a mentor's total effort (own deposits + cross-deposits they brought) for bonus calc."""
    role = user["role"]
    if role not in ["mentor", "master_of_academics", "master_of_academics_", "super_admin", "admin"]:
        raise HTTPException(status_code=403, detail="Access denied")

    USD_TO_AED = float(os.environ.get("USD_TO_AED_RATE", "3.674"))
    date_start, date_end = _get_date_range(period, custom_start, custom_end)
    date_q = {}
    if date_start:
        date_q["date"] = {"$gte": date_start}
        if date_end:
            date_q["date"]["$lt"] = date_end

    mentor_id = user["id"]

    # Own deposits (where mentor_id = user and no effort_by, or effort_by = self)
    own_q = {**date_q, "mentor_id": mentor_id, "$or": [{"effort_by_id": {"$exists": False}}, {"effort_by_id": None}, {"effort_by_id": mentor_id}]}
    own_agg = await db.mentor_redeposits.aggregate([{"$match": own_q}, {"$group": {"_id": None, "total": {"$sum": "$amount"}, "count": {"$sum": 1}}}]).to_list(1)
    own_usd = own_agg[0]["total"] if own_agg else 0
    own_count = own_agg[0]["count"] if own_agg else 0

    # Cross deposits (where effort_by = user but mentor_id != user)
    cross_q = {**date_q, "effort_by_id": mentor_id, "mentor_id": {"$ne": mentor_id}}
    cross_agg = await db.mentor_redeposits.aggregate([{"$match": cross_q}, {"$group": {"_id": None, "total": {"$sum": "$amount"}, "count": {"$sum": 1}}}]).to_list(1)
    cross_usd = cross_agg[0]["total"] if cross_agg else 0
    cross_count = cross_agg[0]["count"] if cross_agg else 0

    total_effort_usd = own_usd + cross_usd
    bonus_tier = _get_bonus_tier(total_effort_usd)

    # Get salary for bonus calc
    hr_emp = await db.hr_employees.find_one({"user_id": mentor_id}, {"_id": 0, "salary_structure": 1, "salary": 1})
    salary = _get_employee_salary_aed(hr_emp)

    # Next tier
    next_tier = None
    for t in reversed(BONUS_TIERS):
        if total_effort_usd < t["min_usd"]:
            next_tier = t
    remaining_for_next = (next_tier["min_usd"] - total_effort_usd) if next_tier else 0

    return {
        "own_deposits_usd": own_usd, "own_deposits_aed": round(own_usd * USD_TO_AED, 2), "own_count": own_count,
        "cross_deposits_usd": cross_usd, "cross_deposits_aed": round(cross_usd * USD_TO_AED, 2), "cross_count": cross_count,
        "total_effort_usd": total_effort_usd, "total_effort_aed": round(total_effort_usd * USD_TO_AED, 2),
        "total_count": own_count + cross_count,
        "bonus_tier": bonus_tier,
        "bonus_amount": round(salary * (bonus_tier["pct"] / 100), 2) if bonus_tier else 0,
        "salary": salary,
        "next_tier": next_tier,
        "remaining_for_next_usd": remaining_for_next,
        "tiers": BONUS_TIERS,
    }




