@api_router.get("/dashboard/mentor-bifurcation")
async def get_mentor_bifurcation(
    period: str = "overall",
    custom_start: Optional[str] = None,
    custom_end: Optional[str] = None,
    user = Depends(require_roles(["super_admin", "admin"]))
):
    query = {"mentor_id": {"$exists": True, "$ne": None}}
    query.update(_build_date_filter("enrolled_at", period, custom_start, custom_end))

    pipeline = [
        {"$match": query},
        {"$group": {
            "_id": "$mentor_id",
            "name": {"$first": "$mentor_name"},
            "total_students": {"$sum": 1},
            "new_students": {"$sum": {"$cond": [{"$eq": ["$mentor_stage", "new_student"]}, 1, 0]}},
            "connected": {"$sum": {"$cond": [{"$ne": ["$mentor_stage", "new_student"]}, 1, 0]}},
        }},
        {"$sort": {"total_students": -1}}
    ]
    students_result = await db.students.aggregate(pipeline).to_list(100)

    # Get redeposit totals per mentor from ltv_transactions
    mentor_data = {}
    for r in students_result:
        mentor_data[r["_id"]] = {
            "mentor_name": r.get("name", "Unknown"),
            "total_students": r["total_students"],
            "new_students": r.get("new_students", 0),
            "connected": r.get("connected", 0),
            "redeposits": 0,
            "redeposit_amount": 0,
        }

    # Get redeposits from mentor_redeposits collection
    redeposit_pipeline = [
        {"$group": {
            "_id": "$mentor_user_id",
            "count": {"$sum": 1},
            "total": {"$sum": "$redeposit_amount"}
        }}
    ]
    redeposits = await db.mentor_redeposits.aggregate(redeposit_pipeline).to_list(100)
    for rd in redeposits:
        if rd["_id"] in mentor_data:
            mentor_data[rd["_id"]]["redeposits"] = rd["count"]
            mentor_data[rd["_id"]]["redeposit_amount"] = rd["total"]

    return list(mentor_data.values())

@api_router.get("/dashboard/activity-summary")
async def get_activity_summary(
    period: str = "today",
    user = Depends(require_roles(["super_admin", "admin"]))
):
    """Activity summary with date filters for super admin overview."""
    start_date = _get_date_range(period)
    date_filter = {"enrolled_at": {"$gte": start_date}} if start_date else {}

    # New enrollments in period
    new_enrollments = await db.leads.count_documents({"stage": "enrolled", "is_historical": True, **date_filter})

    # New students assigned in period
    new_students = await db.students.count_documents({"is_historical": True, **date_filter})

    # Revenue in period
    rev_query = {}
    if start_date:
        rev_query["date"] = {"$gte": start_date}
    rev_pipeline = [
        {"$match": rev_query},
        {"$group": {"_id": None, "total": {"$sum": "$amount"}, "count": {"$sum": 1}}}
    ]
    rev_result = await db.ltv_transactions.aggregate(rev_pipeline).to_list(1)
    total_revenue = rev_result[0]["total"] if rev_result else 0
    transaction_count = rev_result[0]["count"] if rev_result else 0

    # Sales by course in period
    course_pipeline = [
        {"$match": {"stage": "enrolled", **date_filter}},
        {"$group": {
            "_id": "$course_of_interest",
            "count": {"$sum": 1},
            "revenue": {"$sum": "$enrollment_amount"}
        }},
        {"$sort": {"revenue": -1}},
        {"$limit": 10}
    ]
    sales_by_course = await db.leads.aggregate(course_pipeline).to_list(10)

    return {
        "period": period,
        "new_enrollments": new_enrollments,
        "new_students": new_students,
        "total_revenue": total_revenue,
        "transaction_count": transaction_count,
        "sales_by_course": [{"course": r["_id"], "count": r["count"], "revenue": r.get("revenue", 0)} for r in sales_by_course],
    }


@api_router.get("/dashboard/today-transactions")
async def get_today_transactions(view_mode: str = "personal", user = Depends(get_current_user)):
    """Get all transactions (enrollments + upgrades) that happened today"""
    today = datetime.now(timezone.utc).isoformat()[:10]
    
    # 1. LTV transactions (upgrades, deposits)
    ltv_txns = await db.ltv_transactions.find(
        {"date": today}, {"_id": 0}
    ).sort("created_at", -1).to_list(100)
    
    # 2. Today's enrollments from leads (based on enrolled_at)
    enroll_query = {"stage": "enrolled", "enrolled_at": {"$gte": today}}
    if view_mode == "personal" and user["role"] == "sales_executive":
        enroll_query["assigned_to"] = user["id"]
    elif view_mode == "personal" and user["role"] == "team_leader":
        team = await db.users.find({"team_leader_id": user["id"]}, {"_id": 0, "id": 1}).to_list(100)
        team_ids = [t["id"] for t in team] + [user["id"]]
        enroll_query["assigned_to"] = {"$in": team_ids}
    
    enrolled_today = await db.leads.find(
        enroll_query,
        {"_id": 0, "id": 1, "full_name": 1, "enrollment_amount": 1, "sale_amount": 1, 
         "enrolled_at": 1, "assigned_to_name": 1, "course_name": 1, "interested_course_name": 1}
    ).sort("enrolled_at", -1).to_list(100)
    
    # Convert enrollments to transaction format (avoid duplicates with ltv_transactions)
    # ltv_transactions use student_id, so map student_id → lead_id via students collection
    ltv_student_ids = [t.get("student_id") for t in ltv_txns if t.get("student_id")]
    ltv_linked_lead_ids = set()
    if ltv_student_ids:
        linked_students = await db.students.find(
            {"id": {"$in": ltv_student_ids}}, {"_id": 0, "lead_id": 1}
        ).to_list(500)
        ltv_linked_lead_ids = {s["lead_id"] for s in linked_students if s.get("lead_id")}
    
    enrollment_txns = []
    for e in enrolled_today:
        if e["id"] not in ltv_linked_lead_ids:
            enrollment_txns.append({
                "id": e["id"],
                "student_name": e["full_name"],
                "type": "enrollment",
                "amount": e.get("enrollment_amount") or e.get("sale_amount", 0),
                "description": f"New Enrollment: {e.get('course_name') or e.get('interested_course_name') or 'N/A'}",
                "course_name": e.get("course_name") or e.get("interested_course_name"),
                "agent_name": e.get("assigned_to_name"),
                "date": today,
                "created_at": e.get("enrolled_at"),
            })
    
    all_transactions = sorted(ltv_txns + enrollment_txns, key=lambda x: x.get("created_at", ""), reverse=True)
    total = sum(t.get("amount", 0) for t in all_transactions)
    
    return {
        "date": today,
        "count": len(all_transactions),
        "total_amount": total,
        "transactions": all_transactions
    }


@api_router.get("/dashboard/team-revenue")
async def get_team_revenue(
    period: str = "overall",
    custom_start: Optional[str] = None,
    custom_end: Optional[str] = None,
    user = Depends(get_current_user)
):
    """Team-wise revenue with individual agent drill-down."""
    cache_key = f"team_revenue_{period}_{custom_start}_{custom_end}"
    cached = _cache.get(cache_key, ttl=60)
    if cached:
        return cached
    
    query = {"stage": "enrolled", "team_name": {"$exists": True, "$ne": None}}
    query.update(_build_date_filter("enrolled_at", period, custom_start, custom_end))

    pipeline = [
        {"$match": query},
        {"$group": {
            "_id": "$team_name",
            "team_id": {"$first": "$team_id"},
            "deals": {"$sum": 1},
            "revenue": {"$sum": {"$ifNull": ["$enrollment_amount", 0]}},
        }},
        {"$sort": {"revenue": -1}}
    ]
    result = await db.leads.aggregate(pipeline).to_list(50)
    response = [{"team_name": r["_id"], "team_id": r.get("team_id"), "deals": r["deals"], "revenue": r["revenue"]} for r in result if r["_id"]]
    _cache.set(cache_key, response)
    return response

