@api_router.get("/import/templates/historical-sales/download")
async def download_historical_sales_template_xlsx(token: str = None, request: Request = None):
    """Download Excel template with Sheet 1: Import Template, Sheet 2: Courses with Prices, Sheet 3: Teams & Agents."""
    import openpyxl
    from openpyxl.styles import Font, PatternFill, Alignment, Border, Side
    import io
    
    # Verify token
    auth_token = token
    if not auth_token and request:
        auth_header = request.headers.get("Authorization", "")
        if auth_header.startswith("Bearer "):
            auth_token = auth_header[7:]
    if auth_token:
        try:
            jwt.decode(auth_token, SECRET_KEY, algorithms=["HS256"])
        except:
            pass
    
    wb = openpyxl.Workbook()
    ws1 = wb.active
    ws1.title = "Historical Sales Data"
    
    header_labels = ["Full Name *", "Phone *", "Course Enrolled *", "Course Amount (AED)",
                     "Add-ons", "Add-on Amount (AED)", "Agent Name *", "Team Name *",
                     "Enrolled Amount (AED)", "Enrolled At (YYYY-MM-DD)", "Email", "Country", "City", "Source"]
    header_font = Font(bold=True, color="FFFFFF", size=11)
    header_fill = PatternFill(start_color="2563EB", end_color="2563EB", fill_type="solid")
    req_fill = PatternFill(start_color="DBEAFE", end_color="DBEAFE", fill_type="solid")
    thin_border = Border(left=Side(style='thin'), right=Side(style='thin'), top=Side(style='thin'), bottom=Side(style='thin'))
    
    for col, label in enumerate(header_labels, 1):
        cell = ws1.cell(row=1, column=col, value=label)
        cell.font = header_font
        cell.fill = header_fill
        cell.alignment = Alignment(horizontal='center', wrap_text=True)
        cell.border = thin_border
    
    example = ["Ahmed Ali", "+971501234567", "Basic Course", "1999",
               "Whatsapp community, Ebook", "108", "Kiran VR", "TEAM XLNC",
               "2107", "2025-06-15", "ahmed@example.com", "UAE", "Dubai", "Meta Ads"]
    for col, val in enumerate(example, 1):
        cell = ws1.cell(row=2, column=col, value=val)
        cell.border = thin_border
        if col <= 3 or col in [7, 8]:
            cell.fill = req_fill
    
    widths = [20, 18, 22, 18, 28, 18, 20, 22, 18, 22, 25, 12, 12, 15]
    for col, w in enumerate(widths, 1):
        ws1.column_dimensions[openpyxl.utils.get_column_letter(col)].width = w
    
    # Sheet 2: Courses (from course_catalog) with commission info
    ws2 = wb.create_sheet("Courses & Prices")
    ch_fill = PatternFill(start_color="059669", end_color="059669", fill_type="solid")
    course_headers = ["Course Name", "Price (AED)", "Type", "Commission SE (AED)", "Commission TL (AED)", "Commission SM (AED)"]
    for col, h in enumerate(course_headers, 1):
        cell = ws2.cell(row=1, column=col, value=h)
        cell.font = Font(bold=True, color="FFFFFF", size=11)
        cell.fill = ch_fill
        cell.alignment = Alignment(horizontal='center')
        cell.border = thin_border
    catalog_courses = await db.course_catalog.find({"type": {"$in": ["course", "upgrade"]}, "is_active": True}, {"_id": 0}).sort("type", 1).to_list(200)
    # Fallback to legacy courses if catalog is empty
    if not catalog_courses:
        legacy = await db.courses.find({}, {"_id": 0, "name": 1, "price": 1, "category": 1}).sort("name", 1).to_list(200)
        catalog_courses = [{"name": c.get("name", ""), "price": c.get("price", 0), "type": c.get("category", "")} for c in legacy]
    for ri, c in enumerate(catalog_courses, 2):
        ws2.cell(row=ri, column=1, value=c.get("name", "")).border = thin_border
        ws2.cell(row=ri, column=2, value=c.get("price") or 0).border = thin_border
        ws2.cell(row=ri, column=3, value=c.get("type", "").title()).border = thin_border
        ws2.cell(row=ri, column=4, value=c.get("commission_sales_executive", 0)).border = thin_border
        ws2.cell(row=ri, column=5, value=c.get("commission_team_leader", 0)).border = thin_border
        ws2.cell(row=ri, column=6, value=c.get("commission_sales_manager", 0)).border = thin_border
    for col, w in zip(range(1, 7), [30, 15, 15, 20, 20, 20]):
        ws2.column_dimensions[openpyxl.utils.get_column_letter(col)].width = w
    
    # Sheet 3: Add-ons & Prices (from course_catalog)
    ws_addons = wb.create_sheet("Add-ons & Prices")
    addon_fill = PatternFill(start_color="7C3AED", end_color="7C3AED", fill_type="solid")
    for col, h in enumerate(["Add-on Name", "Price (AED)"], 1):
        cell = ws_addons.cell(row=1, column=col, value=h)
        cell.font = Font(bold=True, color="FFFFFF", size=11)
        cell.fill = addon_fill
        cell.alignment = Alignment(horizontal='center')
        cell.border = thin_border
    catalog_addons = await db.course_catalog.find({"type": "addon", "is_active": True}, {"_id": 0, "name": 1, "price": 1}).sort("name", 1).to_list(200)
    for ri, a in enumerate(catalog_addons, 2):
        ws_addons.cell(row=ri, column=1, value=a.get("name", "")).border = thin_border
        ws_addons.cell(row=ri, column=2, value=a.get("price") or 0).border = thin_border
    ws_addons.column_dimensions['A'].width = 30
    ws_addons.column_dimensions['B'].width = 15
    
    # Sheet 4: Teams & Agents
    ws3 = wb.create_sheet("Teams & Agents")
    ta_fill = PatternFill(start_color="D97706", end_color="D97706", fill_type="solid")
    for col, h in enumerate(["Agent Name", "Team Name"], 1):
        cell = ws3.cell(row=1, column=col, value=h)
        cell.font = Font(bold=True, color="FFFFFF", size=11)
        cell.fill = ta_fill
        cell.alignment = Alignment(horizontal='center')
        cell.border = thin_border
    sales_agents = await db.users.find({"role": {"$in": ["sales_executive", "team_leader", "sales_manager"]}}, {"_id": 0, "full_name": 1, "team_id": 1}).to_list(200)
    for ri, agent in enumerate(sales_agents, 2):
        ws3.cell(row=ri, column=1, value=agent.get("full_name", "")).border = thin_border
        team = await db.teams.find_one({"id": agent.get("team_id")}, {"_id": 0, "name": 1}) if agent.get("team_id") else None
        ws3.cell(row=ri, column=2, value=team.get("name", "") if team else "").border = thin_border
    ws3.column_dimensions['A'].width = 25
    ws3.column_dimensions['B'].width = 25
    
    output = io.BytesIO()
    wb.save(output)
    output.seek(0)
    
    return StreamingResponse(output, media_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        headers={"Content-Disposition": "attachment; filename=historical_sales_import_template.xlsx"})


@api_router.get("/import/templates/cs-historical/download")
async def download_cs_historical_template(token: str = None, request: Request = None):
    """Download CS historical import Excel template with upgrade courses and CS agents."""
    import openpyxl
    from openpyxl.styles import Font, Alignment, PatternFill, Border, Side
    import io as _io
    
    auth_token = token
    if not auth_token and request:
        auth_header = request.headers.get("Authorization", "")
        if auth_header.startswith("Bearer "):
            auth_token = auth_header[7:]
    if auth_token:
        try:
            jwt.decode(auth_token, SECRET_KEY, algorithms=["HS256"])
        except:
            pass
    
    wb = openpyxl.Workbook()
    ws1 = wb.active
    ws1.title = "CS Historical Data"
    
    header_labels = ["Full Name *", "Phone *", "Course Upgrade *", "Course Amount (AED)",
                     "CS Agent Name *", "Date (YYYY-MM-DD)", "Email"]
    header_font = Font(bold=True, color="FFFFFF", size=11)
    header_fill = PatternFill(start_color="059669", end_color="059669", fill_type="solid")
    req_fill = PatternFill(start_color="D1FAE5", end_color="D1FAE5", fill_type="solid")
    thin_border = Border(left=Side(style='thin'), right=Side(style='thin'), top=Side(style='thin'), bottom=Side(style='thin'))
    
    for col, label in enumerate(header_labels, 1):
        cell = ws1.cell(row=1, column=col, value=label)
        cell.font = header_font
        cell.fill = header_fill
        cell.alignment = Alignment(horizontal='center', wrap_text=True)
        cell.border = thin_border
    
    example = ["Ahmed Ali", "+971501234567", "Upgrade", "2105", "Falja Nizar", "2025-02-15", "ahmed@example.com"]
    for col, val in enumerate(example, 1):
        cell = ws1.cell(row=2, column=col, value=val)
        cell.border = thin_border
        if col in [1, 2, 3, 5]:
            cell.fill = req_fill
    
    widths = [22, 18, 22, 18, 22, 20, 28]
    for col, w in enumerate(widths, 1):
        ws1.column_dimensions[openpyxl.utils.get_column_letter(col)].width = w
    
    # Sheet 2: CS Agents
    ws2 = wb.create_sheet("CS Agents")
    agent_fill = PatternFill(start_color="2563EB", end_color="2563EB", fill_type="solid")
    for col, h in enumerate(["Agent Name", "Role"], 1):
        cell = ws2.cell(row=1, column=col, value=h)
        cell.font = Font(bold=True, color="FFFFFF", size=11)
        cell.fill = agent_fill
        cell.alignment = Alignment(horizontal='center')
        cell.border = thin_border
    cs_agents = await db.users.find({"role": {"$in": ["cs_agent", "cs_head", "cs_manager"]}}, {"_id": 0, "full_name": 1, "role": 1}).sort("full_name", 1).to_list(50)
    for ri, a in enumerate(cs_agents, 2):
        ws2.cell(row=ri, column=1, value=a.get("full_name", "")).border = thin_border
        ws2.cell(row=ri, column=2, value=a.get("role", "")).border = thin_border
    ws2.column_dimensions['A'].width = 25
    ws2.column_dimensions['B'].width = 15
    
    # Sheet 3: Upgrade Courses (from course_catalog)
    ws3 = wb.create_sheet("Upgrade Courses")
    upgrade_fill = PatternFill(start_color="D97706", end_color="D97706", fill_type="solid")
    for col, h in enumerate(["Course Name", "Price (AED)"], 1):
        cell = ws3.cell(row=1, column=col, value=h)
        cell.font = Font(bold=True, color="FFFFFF", size=11)
        cell.fill = upgrade_fill
        cell.alignment = Alignment(horizontal='center')
        cell.border = thin_border
    upgrades = await db.course_catalog.find({"type": "upgrade", "is_active": True}, {"_id": 0, "name": 1, "price": 1}).sort("name", 1).to_list(50)
    for ri, u in enumerate(upgrades, 2):
        ws3.cell(row=ri, column=1, value=u.get("name", "")).border = thin_border
        ws3.cell(row=ri, column=2, value=u.get("price") or 0).border = thin_border
    ws3.column_dimensions['A'].width = 25
    ws3.column_dimensions['B'].width = 15
    
    # Sheet 4: Existing Students (for correct mapping)
    ws4 = wb.create_sheet("Students")
    student_fill = PatternFill(start_color="7C3AED", end_color="7C3AED", fill_type="solid")
    for col, h in enumerate(["Student Name", "Email", "Phone"], 1):
        cell = ws4.cell(row=1, column=col, value=h)
        cell.font = Font(bold=True, color="FFFFFF", size=11)
        cell.fill = student_fill
        cell.alignment = Alignment(horizontal='center')
        cell.border = thin_border
    students = await db.students.find({}, {"_id": 0, "full_name": 1, "email": 1, "phone": 1}).sort("full_name", 1).to_list(5000)
    for ri, s in enumerate(students, 2):
        ws4.cell(row=ri, column=1, value=s.get("full_name", "")).border = thin_border
        ws4.cell(row=ri, column=2, value=s.get("email", "")).border = thin_border
        ws4.cell(row=ri, column=3, value=s.get("phone", "")).border = thin_border
    ws4.column_dimensions['A'].width = 25
    ws4.column_dimensions['B'].width = 30
    ws4.column_dimensions['C'].width = 18
    
    output = _io.BytesIO()
    wb.save(output)
    output.seek(0)
    
    return StreamingResponse(
        output,
        media_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        headers={"Content-Disposition": "attachment; filename=cs_historical_import_template.xlsx"}
    )


