class UserProfileUpdate(BaseModel):
    full_name: Optional[str] = None
    phone: Optional[str] = None
    additional_phones: Optional[List[str]] = None
    profile_photo_url: Optional[str] = None
    bio: Optional[str] = None

@api_router.put("/users/me/profile")
async def update_my_profile(data: UserProfileUpdate, user = Depends(get_current_user)):
    """Update current user's profile (self-service)"""
    update_data = {}
    
    if data.full_name:
        update_data["full_name"] = data.full_name
    if data.phone:
        update_data["phone"] = data.phone
    if data.additional_phones is not None:
        update_data["additional_phones"] = data.additional_phones
    if data.profile_photo_url is not None:
        update_data["profile_photo_url"] = data.profile_photo_url
    if data.bio is not None:
        update_data["bio"] = data.bio
    
    if not update_data:
        raise HTTPException(status_code=400, detail="No fields to update")
    
    update_data["updated_at"] = datetime.now(timezone.utc).isoformat()
    
    await db.users.update_one({"id": user["id"]}, {"$set": update_data})
    
    # Log the update
    await log_audit(
        user,
        "profile_update",
        "user",
        entity_id=user["id"],
        entity_name=user.get("full_name"),
        details={"fields_updated": list(update_data.keys())}
    )
    
    updated_user = await db.users.find_one({"id": user["id"]}, {"_id": 0, "password": 0})
    return updated_user

@api_router.post("/users/me/profile-photo")
async def upload_profile_photo(file: UploadFile, user = Depends(get_current_user)):
    """Upload profile photo"""
    import base64
    
    # Validate file type
    allowed_types = ["image/jpeg", "image/png", "image/gif", "image/webp"]
    if file.content_type not in allowed_types:
        raise HTTPException(status_code=400, detail="Invalid file type. Only JPEG, PNG, GIF, WebP allowed.")
    
    # Read and convert to base64 (simple storage for now)
    contents = await file.read()
    if len(contents) > 2 * 1024 * 1024:  # 2MB limit
        raise HTTPException(status_code=400, detail="File too large. Maximum 2MB allowed.")
    
    # Store as base64 data URL
    b64 = base64.b64encode(contents).decode('utf-8')
    data_url = f"data:{file.content_type};base64,{b64}"
    
    await db.users.update_one(
        {"id": user["id"]},
        {"$set": {"profile_photo_url": data_url, "updated_at": datetime.now(timezone.utc).isoformat()}}
    )
    
    return {"message": "Profile photo uploaded", "photo_url": data_url[:100] + "..."}

# ==================== MENTOR LEADERBOARD ====================

@api_router.get("/mentor/leaderboard")
async def get_mentor_leaderboard(
    period: str = "monthly",  # monthly, quarterly, yearly, all_time
    user = Depends(get_current_user)
):
    """Get mentor leaderboard ranked by total redeposit effort (own + cross-mentor deposits)."""
    now = datetime.now(timezone.utc)
    USD_TO_AED = float(os.environ.get("USD_TO_AED_RATE", "3.674"))

    # Define date range
    if period == "monthly":
        start_date = now.replace(day=1, hour=0, minute=0, second=0, microsecond=0)
    elif period == "quarterly":
        quarter_start_month = ((now.month - 1) // 3) * 3 + 1
        start_date = now.replace(month=quarter_start_month, day=1, hour=0, minute=0, second=0, microsecond=0)
    elif period == "yearly":
        start_date = now.replace(month=1, day=1, hour=0, minute=0, second=0, microsecond=0)
    else:  # all_time
        start_date = datetime(2020, 1, 1, tzinfo=timezone.utc)

    date_str = start_date.isoformat()[:10]

    # Get all active mentors
    mentors = await db.users.find(
        {"role": {"$in": ["mentor", "academic_master", "master_of_academics", "master_of_academics_"]}, "is_active": True},
        {"_id": 0, "id": 1, "full_name": 1, "email": 1, "department": 1}
    ).to_list(100)

    mentor_ids = [m["id"] for m in mentors]
    mentor_map = {m["id"]: m for m in mentors}

    # Aggregate effort per mentor: own deposits (mentor_id match, no effort_by or self) + cross deposits (effort_by match)
    # We need to compute "effort_by" for each deposit and group by the person who made the effort
    effort_pipeline = [
        {"$match": {"date": {"$gte": date_str}}},
        {"$addFields": {
            "effective_effort_by": {
                "$cond": {
                    "if": {"$and": [{"$ne": ["$effort_by_id", None]}, {"$gt": [{"$type": "$effort_by_id"}, "null"]}]},
                    "then": "$effort_by_id",
                    "else": "$mentor_id"
                }
            }
        }},
        {"$group": {
            "_id": "$effective_effort_by",
            "total_effort_usd": {"$sum": "$amount"},
            "deposit_count": {"$sum": 1},
        }},
        {"$sort": {"total_effort_usd": -1}},
    ]
    effort_data = {d["_id"]: d for d in await db.mentor_redeposits.aggregate(effort_pipeline).to_list(200)}

    # Also get student counts per mentor
    student_pipeline = [
        {"$match": {"mentor_id": {"$in": mentor_ids}}},
        {"$group": {"_id": "$mentor_id", "count": {"$sum": 1}}},
    ]
    student_counts = {d["_id"]: d["count"] for d in await db.students.aggregate(student_pipeline).to_list(200)}

    leaderboard = []
    for m in mentors:
        mid = m["id"]
        eff = effort_data.get(mid, {})
        total_effort_usd = eff.get("total_effort_usd", 0)
        total_effort_aed = round(total_effort_usd * USD_TO_AED, 2)
        deposit_count = eff.get("deposit_count", 0)
        bonus_tier = _get_bonus_tier(total_effort_usd)

        leaderboard.append({
            "mentor_id": mid,
            "mentor_name": m.get("full_name"),
            "email": m.get("email"),
            "department": m.get("department"),
            "total_students": student_counts.get(mid, 0),
            "total_effort_usd": total_effort_usd,
            "total_effort_aed": total_effort_aed,
            "deposit_count": deposit_count,
            "bonus_tier": bonus_tier.get("pct") if bonus_tier else None,
            "bonus_tier_label": f'{bonus_tier["pct"]}%' if bonus_tier else "-",
        })

    # Sort by total effort (highest first)
    leaderboard.sort(key=lambda x: x["total_effort_usd"], reverse=True)

    # Add ranks
    for i, entry in enumerate(leaderboard):
        entry["rank"] = i + 1

    return {
        "period": period,
        "start_date": start_date.isoformat(),
        "leaderboard": leaderboard,
        "total_mentors": len(leaderboard)
    }

# ==================== QUICK STATS WIDGET ====================

@api_router.get("/dashboard/quick-stats")
async def get_quick_stats(user = Depends(get_current_user)):
    """Get quick stats for home launcher widget - accurate, role-based"""
    now = datetime.now(timezone.utc)
    today_start = now.replace(hour=0, minute=0, second=0, microsecond=0)
    month_start = now.replace(day=1, hour=0, minute=0, second=0, microsecond=0)
    
    stats = {}
    role = user.get("role")
    
    # Role-specific lead scope
    if role in ["super_admin", "admin", "sales_manager", "team_leader", "sales_executive"]:
        if role == "sales_executive":
            lead_query = {"assigned_to": user["id"]}
        elif role == "team_leader":
            team_members = await db.users.find({"team_id": user.get("team_id")}).to_list(100)
            team_ids = [t["id"] for t in team_members] + [user["id"]]
            lead_query = {"assigned_to": {"$in": team_ids}}
        else:
            lead_query = {}
        
        # Active pipeline (excludes enrolled, rejected, pool)
        stats["active_pipeline"] = await db.leads.count_documents({
            **lead_query,
            "stage": {"$nin": ["enrolled", "rejected", "not_interested"]},
            "in_pool": {"$ne": True}
        })
        
        # New leads today (only valid timestamps, skip bad data like "N")
        stats["new_leads_today"] = await db.leads.count_documents({
            **lead_query,
            "created_at": {"$gte": today_start.isoformat(), "$regex": "^20"}
        })
        
        # Enrolled this month — use students created_at (student is created on enrollment)
        student_month_query = {"created_at": {"$gte": month_start.isoformat(), "$regex": "^20"}}
        stats["enrolled_mtd"] = await db.students.count_documents(student_month_query)
        
        # SLA breaches (active)
        stats["sla_breaches"] = await db.leads.count_documents({
            **lead_query,
            "sla_status": {"$in": ["breach", "warning"]},
            "stage": {"$nin": ["enrolled", "rejected"]}
        })
    
    if role in ["super_admin", "admin", "cs_head", "cs_agent"]:
        if role == "cs_agent":
            student_query = {"cs_agent_id": user["id"]}
        else:
            student_query = {}
        
        stats["total_students"] = await db.students.count_documents(student_query)
        stats["pending_activation"] = await db.students.count_documents({
            **student_query,
            "stage": "new_student"
        })
        stats["new_students_today"] = await db.students.count_documents({
            **student_query,
            "created_at": {"$gte": today_start.isoformat(), "$regex": "^20"}
        })
    
    if role in ["super_admin", "admin", "mentor", "academic_master", "master_of_academics", "master_of_academics_"]:
        if role in ["mentor", "academic_master", "master_of_academics", "master_of_academics_"]:
            mentor_query = {"mentor_id": user["id"]}
        else:
            mentor_query = {}
        
        stats["mentor_students"] = await db.students.count_documents({**mentor_query, "mentor_id": {"$exists": True}})
        stats["upgrade_opportunities"] = await db.students.count_documents({
            **mentor_query,
            "upgrade_eligible": True,
            "upgrade_closed": {"$ne": True}
        })
    
    if role in ["super_admin", "admin", "finance"]:
        stats["pending_payments"] = await db.payments.count_documents({"stage": "pending_verification"})
        
        # MTD Revenue (verified payments)
        revenue_pipeline = [
            {"$match": {
                "stage": "verified",
                "created_at": {"$gte": month_start.isoformat()}
            }},
            {"$group": {"_id": None, "total": {"$sum": "$amount"}}}
        ]
        revenue_result = await db.payments.aggregate(revenue_pipeline).to_list(1)
        stats["mtd_revenue"] = revenue_result[0]["total"] if revenue_result else 0
    
    # Common stats
    stats["pending_followups"] = await db.leads.count_documents({
        "reminder_date": {"$lte": now.isoformat()},
        "reminder_completed": {"$ne": True}
    })
    stats["unread_notifications"] = await db.notifications.count_documents({
        "user_id": user["id"],
        "read": False
    })
    
    return stats

