# Salary Structure Model for validation
class SalaryStructure(BaseModel):
    basic_salary: float = 0
    housing_allowance: float = 0
    transport_allowance: float = 0
    telephone_allowance: float = 0
    other_allowances: float = 0
    deductions: float = 0
    commission: float = 0
    incentives: float = 0
    payment_frequency: str = "monthly"
    currency: str = "AED"
    
    @property
    def gross_salary(self) -> float:
        return (self.basic_salary + self.housing_allowance + self.transport_allowance + 
                self.telephone_allowance + self.other_allowances + self.commission + self.incentives)
    
    @property
    def net_salary(self) -> float:
        return self.gross_salary - self.deductions

def _normalize_date(val: str) -> str:
    """Normalize date strings to YYYY-MM-DD format"""
    if not val:
        return val
    # Already YYYY-MM-DD (or YYYY-MM-DD HH:MM:SS)
    if len(val) >= 10 and val[4] == '-':
        return val[:10]
    # DD/MM/YYYY, DD-MM-YYYY, or MM/DD/YYYY formats
    for sep in ['/', '-']:
        parts = val.split(sep)
        if len(parts) == 3:
            a, b, y = parts
            if len(y) == 4 and len(a) <= 2 and len(b) <= 2:
                a_int, b_int = int(a), int(b)
                # If second number > 12, it must be a day → format is MM/DD/YYYY
                if b_int > 12 and a_int <= 12:
                    return f"{y}-{a.zfill(2)}-{b.zfill(2)}"
                # Default: assume DD/MM/YYYY
                return f"{y}-{b.zfill(2)}-{a.zfill(2)}"
    return val

def _normalize_date_us(val: str) -> str:
    """Normalize date strings to YYYY-MM-DD, assuming US (MM/DD/YYYY) format for ambiguous dates."""
    if not val:
        return val
    # Already YYYY-MM-DD (or YYYY-MM-DD HH:MM:SS) from datetime objects
    if len(val) >= 10 and val[4] == '-':
        return val[:10]
    # MM/DD/YYYY format (US)
    for sep in ['/', '-']:
        parts = val.split(sep)
        if len(parts) == 3:
            a, b, y = parts
            if len(y) == 4 and len(a) <= 2 and len(b) <= 2:
                # Always treat as MM/DD/YYYY (US format)
                return f"{y}-{a.zfill(2)}-{b.zfill(2)}"
    return val

@api_router.get("/hr/employees", response_model=List[EmployeeResponse])
async def get_employees(
    department: Optional[str] = None,
    status: Optional[str] = None,
    location: Optional[str] = None,
    search: Optional[str] = None,
    user = Depends(require_roles(["super_admin", "admin", "hr"]))
):
    """Get all employees with optional filters"""
    query = {}
    
    if department:
        query["department"] = department
    if status:
        query["employment_status"] = status
    if location:
        query["work_location"] = location
    if search:
        query["$or"] = [
            {"full_name": {"$regex": search, "$options": "i"}},
            {"employee_id": {"$regex": search, "$options": "i"}},
            {"company_email": {"$regex": search, "$options": "i"}},
            {"mobile_number": {"$regex": search, "$options": "i"}}
        ]
    
    employees = await db.hr_employees.find(query, {"_id": 0}).sort("employee_id", 1).to_list(500)
    
    # Normalize date formats and enrich with reporting manager names
    manager_ids = list({e["reporting_manager_id"] for e in employees if e.get("reporting_manager_id")})
    if manager_ids:
        managers = await db.hr_employees.find({"id": {"$in": manager_ids}}, {"_id": 0, "id": 1, "full_name": 1}).to_list(len(manager_ids))
        manager_map = {m["id"]: m["full_name"] for m in managers}
    else:
        manager_map = {}
    
    for emp in employees:
        # Normalize date fields to YYYY-MM-DD
        for date_field in ["joining_date", "date_of_birth", "confirmation_date", "termination_date"]:
            val = emp.get(date_field)
            if val and isinstance(val, str):
                emp[date_field] = _normalize_date(val)
        
        emp["reporting_manager_name"] = manager_map.get(emp.get("reporting_manager_id"))
    
    return employees

@api_router.get("/hr/employees/next-id")
async def get_next_employee_id(prefix: str = "CLT", user = Depends(require_roles(["super_admin", "admin", "hr"]))):
    """Get the next available employee ID"""
    # Find the highest existing ID with this prefix
    employees = await db.hr_employees.find(
        {"employee_id": {"$regex": f"^{prefix}-"}},
        {"employee_id": 1, "_id": 0}
    ).sort("employee_id", -1).limit(1).to_list(1)
    
    if employees:
        last_id = employees[0]["employee_id"]
        try:
            last_num = int(last_id.split("-")[-1])
            next_num = last_num + 1
        except:
            next_num = 1
    else:
        next_num = 1
    
    return {"next_employee_id": f"{prefix}-{str(next_num).zfill(3)}"}

