async def _calculate_attendance_status(emp: dict, biometric_in: str, biometric_out: str, date_str: str, shift_cache: dict = None, rules_cache: dict = None, warning_counts: dict = None):
    """
    Calculate attendance status based on shift, rules, and warning count.
    Returns dict with: status, late_minutes, total_work_hours, warning_flag, half_day_reason
    """
    # Get employee's shift (use cache if provided)
    shift_id = emp.get("shift_id", "morning")
    if shift_cache and shift_id in shift_cache:
        shift = shift_cache[shift_id]
    else:
        shift = await db.hr_shifts.find_one({"id": shift_id}, {"_id": 0})
        if not shift:
            shift = DEFAULT_SHIFTS.get(shift_id, DEFAULT_SHIFTS["morning"])
        if shift_cache is not None:
            shift_cache[shift_id] = shift

    # Get attendance rules (use cache if provided)
    if rules_cache and "rules" in rules_cache:
        rules = rules_cache["rules"]
    else:
        rules = await db.hr_settings.find_one({"type": "attendance_rules"}, {"_id": 0})
        if not rules:
            rules = {"half_day_hours_threshold": 6, "warning_threshold_minutes": 30, "extra_time_offset_minutes": 30, "special_periods": []}
        if rules_cache is not None:
            rules_cache["rules"] = rules

    # Check for special period (e.g., Ramadan)
    full_day_hours = rules.get("full_day_hours_min", 6)
    for sp in rules.get("special_periods", []):
        if sp.get("start_date") and sp.get("end_date"):
            if sp["start_date"] <= date_str <= sp["end_date"]:
                full_day_hours = sp.get("reduced_hours", full_day_hours)
                break

    shift_start = shift.get("start", "10:00")
    shift_end = shift.get("end", "19:00")
    grace = shift.get("grace_minutes", 30)
    warning_threshold = rules.get("warning_threshold_minutes", 30)
    extra_offset = rules.get("extra_time_offset_minutes", 30)

    result = {
        "status": "present",
        "late_minutes": 0,
        "total_work_hours": 0,
        "warning_flag": False,
        "half_day_reason": None,
        "shift_name": shift.get("name", "Morning Shift"),
        "shift_start": shift_start,
        "shift_end": shift_end
    }

    if not biometric_in:
        result["status"] = "absent"
        return result

    try:
        t_in = datetime.strptime(biometric_in[:5], "%H:%M")
        t_shift_start = datetime.strptime(shift_start, "%H:%M")
        t_shift_end = datetime.strptime(shift_end, "%H:%M")

        # Calculate late minutes
        late_mins = max(0, int((t_in - t_shift_start).total_seconds() / 60))
        result["late_minutes"] = late_mins

        # Calculate work hours
        if biometric_out:
            t_out = datetime.strptime(biometric_out[:5], "%H:%M")
            work_hours = (t_out - t_in).total_seconds() / 3600
            result["total_work_hours"] = round(work_hours, 2)

            # Extra time calculation (past shift end)
            extra_mins = max(0, int((t_out - t_shift_end).total_seconds() / 60))

            # Rule: ≤6 hours (or special period hours) = half day
            if work_hours <= full_day_hours:
                result["status"] = "half_day"
                result["half_day_reason"] = f"Worked {round(work_hours, 1)}h (< {full_day_hours}h threshold)"
                return result

            # Rule: Within grace period (≤15 min late) = Present
            if late_mins <= grace:
                result["status"] = "present"
                result["late_minutes"] = 0  # Within grace, don't mark as late
                return result

            # Rule: 15-30 min late but did extra time (≥30 min past shift end) = Full Day
            if late_mins <= warning_threshold and extra_mins >= extra_offset:
                result["status"] = "present"
                result["half_day_reason"] = f"Late {late_mins}min but stayed {extra_mins}min extra"
                return result

            # Rule: 15-30 min late without enough extra = Late
            if late_mins <= warning_threshold:
                result["status"] = "late"
                return result

            # Rule: >30 min late = Warning (1st in month) or Half Day (2nd+ in month)
            if late_mins > warning_threshold:
                # Count warnings this month for this employee
                month_key = date_str[:7]
                if warning_counts is not None:
                    warning_count = warning_counts.get((emp["id"], month_key), 0)
                else:
                    month_start = date_str[:8] + "01"
                    warning_count = await db.hr_attendance.count_documents({
                        "employee_id": emp["id"],
                        "date": {"$gte": month_start, "$lt": date_str},
                        "warning_flag": True
                    })

                if warning_count == 0:
                    # First time this month = Warning
                    result["status"] = "warning"
                    result["warning_flag"] = True
                    result["half_day_reason"] = f"Late {late_mins}min (>30min) — 1st warning this month"
                else:
                    # 2nd+ time = Half Day
                    result["status"] = "half_day"
                    result["warning_flag"] = True
                    result["half_day_reason"] = f"Late {late_mins}min (>30min) — {warning_count + 1}th occurrence, marked half day"
                return result
        else:
            # No punch out — half day
            result["status"] = "half_day"
            result["total_work_hours"] = 4  # assumed
            result["half_day_reason"] = "No punch out recorded"

    except Exception as e:
        logger.warning(f"Attendance calc error for {emp.get('full_name')}: {e}")

    return result

# ==================== INDIA TEAM PUNCH IN/OUT + TIMESHEET ====================

@api_router.post("/hr/punch")
async def punch_in_out(
    data: Dict,
    user = Depends(get_current_user)
):
    """
    Manual punch in/out for remote team members.
    data: { "type": "in" | "out" }
    """
    employee = await db.hr_employees.find_one(
        {"$or": [{"user_id": user["id"]}, {"id": user.get("employee_id")}]},
        {"_id": 0}
    )
    if not employee:
        raise HTTPException(status_code=404, detail="Employee record not found")

    now = datetime.now(timezone.utc)
    today_str = now.strftime("%Y-%m-%d")
    time_str = now.strftime("%H:%M:%S")
    punch_type = data.get("type", "in").lower()

    existing = await db.hr_attendance.find_one({
        "employee_id": employee["id"],
        "date": today_str
    })

    if punch_type == "in":
        if existing and existing.get("biometric_in"):
            raise HTTPException(status_code=400, detail="Already punched in today")

        if existing:
            await db.hr_attendance.update_one(
                {"id": existing["id"]},
                {"$set": {"biometric_in": time_str, "status": "present", "source": "self_punch", "updated_at": now.isoformat()}}
            )
        else:
            record = {
                "id": str(uuid.uuid4()),
                "employee_id": employee["id"],
                "employee_code": employee.get("employee_id"),
                "employee_name": employee.get("full_name"),
                "department": employee.get("department"),
                "date": today_str,
                "biometric_in": time_str,
                "status": "present",
                "source": "self_punch",
                "created_at": now.isoformat(),
                "updated_at": now.isoformat()
            }
            await db.hr_attendance.insert_one(record)

        return {"message": "Punched in successfully", "time": time_str}

    elif punch_type == "out":
        if not existing or not existing.get("biometric_in"):
            raise HTTPException(status_code=400, detail="No punch-in found for today")
        if existing.get("biometric_out"):
            raise HTTPException(status_code=400, detail="Already punched out today")

        # Calculate status using rules engine
        att_status = await _calculate_attendance_status(employee, existing["biometric_in"], time_str, today_str)

        await db.hr_attendance.update_one(
            {"id": existing["id"]},
            {"$set": {
                "biometric_out": time_str,
                "total_work_hours": att_status["total_work_hours"],
                "late_minutes": att_status["late_minutes"],
                "status": att_status["status"],
                "warning_flag": att_status.get("warning_flag", False),
                "half_day_reason": att_status.get("half_day_reason"),
                "shift_name": att_status.get("shift_name"),
                "source": "self_punch",
                "updated_at": now.isoformat()
            }}
        )

        return {
            "message": "Punched out successfully",
            "time": time_str,
            "work_hours": att_status["total_work_hours"],
            "status": att_status["status"]
        }

    raise HTTPException(status_code=400, detail="Invalid punch type. Use 'in' or 'out'")

@api_router.get("/hr/my-punch-status")
async def get_my_punch_status(user = Depends(get_current_user)):
    """Get current user's punch status for today"""
    employee = await db.hr_employees.find_one(
        {"$or": [{"user_id": user["id"]}, {"id": user.get("employee_id")}]},
        {"_id": 0, "id": 1, "full_name": 1, "shift_id": 1, "work_location": 1}
    )
    if not employee:
        return {"has_employee_record": False}

    today_str = datetime.now(timezone.utc).strftime("%Y-%m-%d")
    attendance = await db.hr_attendance.find_one(
        {"employee_id": employee["id"], "date": today_str},
        {"_id": 0}
    )

    shift_id = employee.get("shift_id", "morning")
    shift = await db.hr_shifts.find_one({"id": shift_id}, {"_id": 0})
    if not shift:
        shift = DEFAULT_SHIFTS.get(shift_id, DEFAULT_SHIFTS["morning"])

    return {
        "has_employee_record": True,
        "employee_name": employee.get("full_name"),
        "location": employee.get("work_location", "UAE"),
        "shift": shift,
        "punched_in": bool(attendance and attendance.get("biometric_in")),
        "punched_out": bool(attendance and attendance.get("biometric_out")),
        "punch_in_time": attendance.get("biometric_in") if attendance else None,
        "punch_out_time": attendance.get("biometric_out") if attendance else None,
        "status": attendance.get("status") if attendance else None,
        "work_hours": attendance.get("total_work_hours") if attendance else None
    }

# ==================== DAILY TIMESHEET ====================

@api_router.post("/hr/timesheet")
async def submit_timesheet(data: Dict, user = Depends(get_current_user)):
    """Submit daily timesheet entry"""
    employee = await db.hr_employees.find_one(
        {"$or": [{"user_id": user["id"]}, {"id": user.get("employee_id")}]},
        {"_id": 0}
    )
    if not employee:
        raise HTTPException(status_code=404, detail="Employee record not found")

    now = datetime.now(timezone.utc).isoformat()
    date_str = data.get("date", datetime.now(timezone.utc).strftime("%Y-%m-%d"))

    # Check if already submitted for today
    existing = await db.hr_timesheets.find_one({"employee_id": employee["id"], "date": date_str})

    entry = {
        "employee_id": employee["id"],
        "employee_code": employee.get("employee_id"),
        "employee_name": employee.get("full_name"),
        "department": employee.get("department"),
        "date": date_str,
        "tasks": data.get("tasks", []),  # [{description, hours, project/category}]
        "summary": data.get("summary", ""),
        "total_logged_hours": sum(t.get("hours", 0) for t in data.get("tasks", [])),
        "updated_at": now
    }

    if existing:
        await db.hr_timesheets.update_one({"id": existing["id"]}, {"$set": entry})
        return {"message": "Timesheet updated", "id": existing["id"]}
    else:
        entry["id"] = str(uuid.uuid4())
        entry["created_at"] = now
        await db.hr_timesheets.insert_one(entry)
        entry.pop("_id", None)
        return {"message": "Timesheet submitted", "id": entry["id"]}

@api_router.get("/hr/timesheet")
async def get_timesheets(
    employee_id: Optional[str] = None,
    date: Optional[str] = None,
    start_date: Optional[str] = None,
    end_date: Optional[str] = None,
    user = Depends(get_current_user)
):
    """Get timesheet entries"""
    query = {}

    if user["role"] not in ["super_admin", "admin", "hr", "team_leader"]:
        employee = await db.hr_employees.find_one({"user_id": user["id"]}, {"_id": 0, "id": 1})
        if employee:
            query["employee_id"] = employee["id"]
    elif employee_id:
        query["employee_id"] = employee_id

    if date:
        query["date"] = date
    elif start_date and end_date:
        query["date"] = {"$gte": start_date, "$lte": end_date}

    records = await db.hr_timesheets.find(query, {"_id": 0}).sort("date", -1).to_list(100)
    return records

@api_router.get("/hr/attendance")
async def get_attendance(
    employee_id: Optional[str] = None,
    date: Optional[str] = None,
    start_date: Optional[str] = None,
    end_date: Optional[str] = None,
    department: Optional[str] = None,
    user = Depends(require_roles(["super_admin", "admin", "hr", "team_leader"]))
):
    """Get attendance records with team strength by location"""
    query = {}
    
    if employee_id:
        query["$or"] = [{"employee_id": employee_id}, {"employee_code": employee_id}]
    if date:
        query["date"] = date
    if start_date and end_date:
        query["date"] = {"$gte": start_date, "$lte": end_date}
    if department:
        query["department"] = department
    
    records = await db.hr_attendance.find(query, {"_id": 0}).sort([("date", -1), ("employee_code", 1)]).to_list(1000)
    
    # Team strength by location
    active_employees = await db.hr_employees.find(
        {"employment_status": {"$in": ["active", "probation"]}},
        {"_id": 0, "id": 1, "work_location": 1, "country": 1}
    ).to_list(500)
    
    total_strength = len(active_employees)
    uae_strength = len([e for e in active_employees if (e.get("country") or e.get("work_location") or "UAE") in ["UAE", "Office"]])
    india_strength = len([e for e in active_employees if (e.get("country") or e.get("work_location")) == "India"])
    
    return {
        "records": records,
        "team_strength": {
            "total": total_strength,
            "uae": uae_strength,
            "india": india_strength,
            "other": total_strength - uae_strength - india_strength
        }
    }

# ==================== MANUAL ATTENDANCE IMPORT ====================

@api_router.get("/hr/attendance/template/download")
async def download_attendance_template(
    month: str,
    user = Depends(require_roles(["super_admin", "admin", "hr"]))
):
    """
    Generate and download an XLSX attendance template for a given month.
    Pre-fills all active employees with their salary structure.
    month format: YYYY-MM (e.g. 2026-03)
    """
    import openpyxl
    from openpyxl.styles import Font, PatternFill, Alignment, Border, Side
    from openpyxl.utils import get_column_letter
    import calendar as cal_module
    import io

    # Parse month
    try:
        year, m = month.split("-")
        year, m = int(year), int(m)
        month_name = cal_module.month_name[m]
        total_days = cal_module.monthrange(year, m)[1]
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid month format. Use YYYY-MM")

    # Fetch active employees with salary
    employees = await db.hr_employees.find(
        {"employment_status": {"$in": ["active", "probation"]}},
        {"_id": 0}
    ).sort("employee_id", 1).to_list(500)

    if not employees:
        raise HTTPException(status_code=404, detail="No active employees found")

    # Also fetch approved leave counts for each employee for this month
    month_start = f"{year}-{str(m).zfill(2)}-01"
    month_end = f"{year}-{str(m).zfill(2)}-{total_days}"

    wb = openpyxl.Workbook()
    ws = wb.active
    ws.title = f"Attendance {month_name} {year}"

    # Styles
    header_fill = PatternFill(start_color="1F4E79", end_color="1F4E79", fill_type="solid")
    header_font = Font(name="Calibri", bold=True, color="FFFFFF", size=11)
    title_font = Font(name="Calibri", bold=True, size=14, color="1F4E79")
    sub_font = Font(name="Calibri", italic=True, size=10, color="666666")
    salary_fill = PatternFill(start_color="E8F0FE", end_color="E8F0FE", fill_type="solid")
    input_fill = PatternFill(start_color="FFF9C4", end_color="FFF9C4", fill_type="solid")
    thin_border = Border(
        left=Side(style="thin"), right=Side(style="thin"),
        top=Side(style="thin"), bottom=Side(style="thin")
    )

    # Title rows
    ws.merge_cells("A1:N1")
    ws["A1"] = f"CLT Synapse - Monthly Attendance Sheet"
    ws["A1"].font = title_font
    ws.merge_cells("A2:N2")
    ws["A2"] = f"Month: {month_name} {year}  |  Total Calendar Days: {total_days}  |  DO NOT modify columns A-K (pre-filled)"
    ws["A2"].font = sub_font
    ws.merge_cells("A3:N3")
    ws["A3"] = f"Fill YELLOW columns (L, M, N) with attendance data. Full Days + Half Days + Approved Leaves should not exceed {total_days}."
    ws["A3"].font = Font(name="Calibri", bold=True, size=10, color="B71C1C")

    # Headers (row 5)
    headers = [
        ("A", "Employee ID", 15),
        ("B", "Employee Name", 25),
        ("C", "Department", 18),
        ("D", "Designation", 20),
        ("E", "Basic Salary", 14),
        ("F", "Housing Allowance", 16),
        ("G", "Transport Allowance", 16),
        ("H", "Food Allowance", 14),
        ("I", "Phone Allowance", 14),
        ("J", "Other Allowances", 16),
    ]

    for col_letter, title, width in headers:
        cell = ws[f"{col_letter}5"]
        cell.value = title
        cell.font = header_font
        cell.fill = header_fill
        cell.alignment = Alignment(horizontal="center", vertical="center", wrap_text=True)
        cell.border = thin_border
        ws.column_dimensions[col_letter].width = width

    # Daily columns starting from column K (col 11)
    day_fill = PatternFill(start_color="D5E8D4", end_color="D5E8D4", fill_type="solid")  # light green
    for day in range(1, total_days + 1):
        in_col = 11 + (day - 1) * 2      # K, M, O, ...
        out_col = in_col + 1               # L, N, P, ...
        in_letter = get_column_letter(in_col)
        out_letter = get_column_letter(out_col)

        in_cell = ws.cell(row=5, column=in_col, value=f"Day {day} In")
        in_cell.font = header_font
        in_cell.fill = day_fill
        in_cell.alignment = Alignment(horizontal="center", vertical="center", wrap_text=True)
        in_cell.border = thin_border
        ws.column_dimensions[in_letter].width = 10

        out_cell = ws.cell(row=5, column=out_col, value=f"Day {day} Out")
        out_cell.font = header_font
        out_cell.fill = day_fill
        out_cell.alignment = Alignment(horizontal="center", vertical="center", wrap_text=True)
        out_cell.border = thin_border
        ws.column_dimensions[out_letter].width = 10

    # Summary columns after daily columns
    summary_start = 11 + total_days * 2
    for offset, title in enumerate(["Full Days", "Half Days", "Absent Days"]):
        sc = ws.cell(row=5, column=summary_start + offset, value=title)
        sc.font = header_font
        sc.fill = PatternFill(start_color="FFC000", end_color="FFC000", fill_type="solid")
        sc.alignment = Alignment(horizontal="center", vertical="center", wrap_text=True)
        sc.border = thin_border
        ws.column_dimensions[get_column_letter(summary_start + offset)].width = 12

    # Pre-fetch attendance records for all employees for this month
    month_start_date = f"{year}-{str(m).zfill(2)}-01"
    month_end_date = f"{year}-{str(m).zfill(2)}-{total_days}"
    all_attendance = await db.hr_attendance.find({
        "date": {"$gte": month_start_date, "$lte": month_end_date}
    }, {"_id": 0}).to_list(5000)

    # Build lookup: emp_id -> { date_str -> record }
    att_lookup = {}
    for att in all_attendance:
        eid = att.get("employee_id") or att.get("employee_code")
        d = att.get("date", "")
        if eid not in att_lookup:
            att_lookup[eid] = {}
        att_lookup[eid][d] = att

    # Data rows (starting row 6)
    for idx, emp in enumerate(employees):
        row = idx + 6
        salary = emp.get("salary_structure") or {}

        # Pre-filled columns (A-J) - locked info
        data = [
            emp.get("employee_id", ""),
            emp.get("full_name", ""),
            emp.get("department", ""),
            emp.get("designation", ""),
            salary.get("basic_salary", emp.get("basic_salary", 0)) or 0,
            salary.get("housing_allowance", 0) or 0,
            salary.get("transport_allowance", 0) or 0,
            salary.get("food_allowance", 0) or 0,
            salary.get("phone_allowance", salary.get("telephone_allowance", 0)) or 0,
            salary.get("other_allowances", 0) or 0,
        ]

        for c, val in enumerate(data, 1):
            cell = ws.cell(row=row, column=c, value=val)
            cell.border = thin_border
            cell.fill = salary_fill
            if c >= 5:  # Salary columns - number format
                cell.number_format = '#,##0.00'
                cell.alignment = Alignment(horizontal="right")

        # Daily punch in/out columns (pre-filled from attendance data)
        emp_att = att_lookup.get(emp.get("id"), {})
        # Also try by employee_code
        if not emp_att:
            emp_att = att_lookup.get(emp.get("employee_id"), {})

        full_days = 0
        half_days = 0
        absent_days = 0

        for day in range(1, total_days + 1):
            date_str = f"{year}-{str(m).zfill(2)}-{str(day).zfill(2)}"
            in_col = 11 + (day - 1) * 2
            out_col = in_col + 1
            record = emp_att.get(date_str, {})
            punch_in = record.get("biometric_in", "")
            punch_out = record.get("biometric_out", "")

            in_cell = ws.cell(row=row, column=in_col, value=punch_in or "")
            in_cell.border = thin_border
            in_cell.fill = input_fill
            in_cell.alignment = Alignment(horizontal="center")

            out_cell = ws.cell(row=row, column=out_col, value=punch_out or "")
            out_cell.border = thin_border
            out_cell.fill = input_fill
            out_cell.alignment = Alignment(horizontal="center")

            # Calculate day status for summary
            if punch_in and punch_out:
                try:
                    t_in = datetime.strptime(punch_in[:5], "%H:%M") if len(punch_in) >= 5 else None
                    t_out = datetime.strptime(punch_out[:5], "%H:%M") if len(punch_out) >= 5 else None
                    if t_in and t_out:
                        hours = (t_out - t_in).total_seconds() / 3600
                        if hours >= 6:
                            full_days += 1
                        elif hours >= 3:
                            half_days += 1
                        else:
                            absent_days += 1
                    else:
                        full_days += 1
                except Exception:
                    full_days += 1
            elif punch_in:
                half_days += 1
            elif record.get("status") == "leave":
                pass  # approved leave, don't count as absent
            else:
                # No punch data for this day — leave blank for HR to fill
                pass

        # Summary columns
        ws.cell(row=row, column=summary_start, value=full_days).border = thin_border
        ws.cell(row=row, column=summary_start, value=full_days).alignment = Alignment(horizontal="center")
        ws.cell(row=row, column=summary_start + 1, value=half_days).border = thin_border
        ws.cell(row=row, column=summary_start + 1, value=half_days).alignment = Alignment(horizontal="center")
        ws.cell(row=row, column=summary_start + 2, value=absent_days).border = thin_border
        ws.cell(row=row, column=summary_start + 2, value=absent_days).alignment = Alignment(horizontal="center")

    # Freeze panes: header row + employee ID column
    ws.freeze_panes = "B6"

    # Write to bytes
    buffer = io.BytesIO()
    wb.save(buffer)
    buffer.seek(0)

    filename = f"attendance_template_{month_name}_{year}.xlsx"
    tmp_path = f"/tmp/{filename}"
    with open(tmp_path, "wb") as f:
        f.write(buffer.getvalue())

    return FileResponse(
        tmp_path,
        media_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        filename=filename,
        headers={"Content-Disposition": f'attachment; filename="{filename}"'}
    )


@api_router.post("/hr/attendance/import")
async def import_attendance(
    file: UploadFile = File(...),
    month: str = Form(...),
    user = Depends(require_roles(["super_admin", "admin", "hr"]))
):
    """
    Import monthly attendance from a filled XLSX template.
    Creates daily attendance records in hr_attendance for payroll calculation.
    month format: YYYY-MM
    """
    import openpyxl
    import calendar as cal_module
    import io

    # Parse month
    try:
        year, m = month.split("-")
        year, m = int(year), int(m)
        total_days = cal_module.monthrange(year, m)[1]
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid month format. Use YYYY-MM")

    # Read the uploaded file
    contents = await file.read()
    try:
        wb = openpyxl.load_workbook(io.BytesIO(contents), data_only=True)
        ws = wb.active
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Invalid XLSX file: {str(e)}")

    now = datetime.now(timezone.utc).isoformat()
    results = {"imported": 0, "skipped": 0, "errors": [], "attendance_records_created": 0}

    # Read data rows (starting row 6) with daily punch times
    for row in ws.iter_rows(min_row=6, values_only=False):
        employee_id_val = row[0].value  # Column A: Employee ID
        if not employee_id_val:
            continue

        employee_id_str = str(employee_id_val).strip()

        # Find employee
        emp = await db.hr_employees.find_one({"employee_id": employee_id_str}, {"_id": 0})
        if not emp:
            results["errors"].append(f"{employee_id_str}: Employee not found")
            results["skipped"] += 1
            continue

        # Delete existing imported attendance for this employee+month
        month_start = f"{year}-{str(m).zfill(2)}-01"
        month_end = f"{year}-{str(m).zfill(2)}-{total_days}"
        await db.hr_attendance.delete_many({
            "employee_id": emp["id"],
            "date": {"$gte": month_start, "$lte": month_end},
            "source": "manual_import"
        })

        # Read daily punch-in/out columns starting from column K (index 10)
        records_to_insert = []
        full_days = 0
        half_days = 0
        absent_days = 0
        
        for day in range(1, total_days + 1):
            in_col_idx = 10 + (day - 1) * 2   # Column K=10, M=12, ...
            out_col_idx = in_col_idx + 1
            
            punch_in_val = row[in_col_idx].value if in_col_idx < len(row) else None
            punch_out_val = row[out_col_idx].value if out_col_idx < len(row) else None
            
            punch_in = str(punch_in_val).strip() if punch_in_val else ""
            punch_out = str(punch_out_val).strip() if punch_out_val else ""
            
            if not punch_in and not punch_out:
                continue  # Skip days with no data
            
            date_str = f"{year}-{str(m).zfill(2)}-{str(day).zfill(2)}"
            
            # Determine status and work hours from punch times
            status = "present"
            total_hours = 9  # default full day
            late_minutes = 0
            
            if punch_in and punch_out:
                try:
                    # Handle various time formats (HH:MM, HH:MM:SS, etc.)
                    t_in_str = punch_in[:5] if len(punch_in) >= 5 else punch_in
                    t_out_str = punch_out[:5] if len(punch_out) >= 5 else punch_out
                    t_in = datetime.strptime(t_in_str, "%H:%M")
                    t_out = datetime.strptime(t_out_str, "%H:%M")
                    total_hours = (t_out - t_in).total_seconds() / 3600
                    
                    # Late check (after 9:30 AM)
                    if t_in.hour > 9 or (t_in.hour == 9 and t_in.minute > 30):
                        late_minutes = (t_in.hour - 9) * 60 + (t_in.minute - 30)
                        if late_minutes < 0:
                            late_minutes = 0
                    
                    if total_hours >= 6:
                        status = "present"
                        full_days += 1
                    elif total_hours >= 3:
                        status = "half_day"
                        half_days += 1
                    else:
                        status = "absent"
                        absent_days += 1
                except Exception:
                    full_days += 1  # Default to full day if parse fails
            elif punch_in:
                status = "half_day"
                half_days += 1
                total_hours = 4.5
            
            records_to_insert.append({
                "id": str(uuid.uuid4()),
                "employee_id": emp["id"],
                "employee_code": emp["employee_id"],
                "employee_name": emp["full_name"],
                "department": emp.get("department"),
                "date": date_str,
                "biometric_in": punch_in,
                "biometric_out": punch_out,
                "total_work_hours": round(total_hours, 2),
                "late_minutes": late_minutes,
                "status": status,
                "source": "manual_import",
                "created_at": now,
                "updated_at": now
            })

        if records_to_insert:
            await db.hr_attendance.insert_many(records_to_insert)
            results["attendance_records_created"] += len(records_to_insert)

        results["imported"] += 1

    return {
        "message": f"Attendance import complete. {results['imported']} employees processed, {results['attendance_records_created']} daily records created.",
        **results
    }

