@api_router.get("/admin/pending-deactivations")
async def get_pending_deactivations(user = Depends(require_roles(["super_admin", "admin", "hr"]))):
    """Get list of terminated/resigned employees with pending access deactivation"""
    now = datetime.now(timezone.utc).isoformat()
    
    pending = await db.hr_employees.find({
        "employment_status": {"$in": ["terminated", "resigned"]},
        "access_disable_date": {"$gt": now},
        "user_id": {"$exists": True, "$ne": None},
        "access_disabled": {"$ne": True}
    }, {"_id": 0, "id": 1, "employee_id": 1, "full_name": 1, "company_email": 1, 
        "employment_status": 1, "termination_date": 1, "access_disable_date": 1}).to_list(500)
    
    deactivated = await db.hr_employees.find({
        "employment_status": {"$in": ["terminated", "resigned"]},
        "access_disabled": True
    }, {"_id": 0, "id": 1, "employee_id": 1, "full_name": 1, "company_email": 1,
        "employment_status": 1, "termination_date": 1, "access_disabled_at": 1}).sort("access_disabled_at", -1).to_list(50)
    
    overdue = await db.hr_employees.find({
        "employment_status": {"$in": ["terminated", "resigned"]},
        "access_disable_date": {"$lte": now},
        "user_id": {"$exists": True, "$ne": None},
        "access_disabled": {"$ne": True}
    }, {"_id": 0, "id": 1, "employee_id": 1, "full_name": 1, "company_email": 1,
        "employment_status": 1, "termination_date": 1, "access_disable_date": 1}).to_list(500)
    
    return {
        "pending": pending,
        "overdue": overdue,
        "recently_deactivated": deactivated,
        "counts": {
            "pending": len(pending),
            "overdue": len(overdue),
            "recently_deactivated": len(deactivated)
        }
    }

# ==================== STUDENT MERGE SYSTEM ====================

@api_router.get("/students/{student_id}/duplicates")
async def detect_student_duplicates(student_id: str, user=Depends(get_current_user)):
    """Detect potential duplicate students based on phone, email, and name similarity."""
    student = await db.students.find_one({"id": student_id}, {"_id": 0})
    if not student:
        raise HTTPException(404, "Student not found")
    
    conditions = []
    phone = student.get("phone")
    email = student.get("email")
    name = student.get("full_name", "")
    
    if phone:
        # Match by phone (exact or partial)
        clean_phone = phone.replace("+", "").replace(" ", "").replace("-", "")[-9:]
        conditions.append({"phone": {"$regex": clean_phone, "$options": "i"}})
    if email:
        conditions.append({"email": {"$regex": f"^{email}$", "$options": "i"}})
    if name and len(name) > 2:
        # Match by name parts
        name_parts = name.strip().split()
        for part in name_parts:
            if len(part) > 2:
                conditions.append({"full_name": {"$regex": part, "$options": "i"}})
    
    if not conditions:
        return {"duplicates": [], "student": student}
    
    potential = await db.students.find(
        {"$or": conditions, "id": {"$ne": student_id}, "merged_into": {"$exists": False}},
        {"_id": 0}
    ).to_list(20)
    
    # Score duplicates
    scored = []
    for p in potential:
        score = 0
        reasons = []
        p_phone = (p.get("phone") or "").replace("+", "").replace(" ", "").replace("-", "")
        s_phone = (phone or "").replace("+", "").replace(" ", "").replace("-", "")
        if p_phone and s_phone and (p_phone[-9:] == s_phone[-9:]):
            score += 50
            reasons.append("Same phone number")
        if email and p.get("email") and email.lower() == p.get("email", "").lower():
            score += 40
            reasons.append("Same email")
        if name and p.get("full_name"):
            s_parts = set(name.lower().split())
            p_parts = set(p["full_name"].lower().split())
            overlap = s_parts & p_parts
            if len(overlap) >= 2:
                score += 30
                reasons.append(f"Name overlap: {', '.join(overlap)}")
            elif len(overlap) == 1 and len(s_parts) <= 2:
                score += 15
                reasons.append(f"Partial name match: {', '.join(overlap)}")
        if score >= 15:
            p["match_score"] = min(score, 100)
            p["match_reasons"] = reasons
            scored.append(p)
    
    scored.sort(key=lambda x: x["match_score"], reverse=True)
    return {"duplicates": scored[:10], "student": student}


@api_router.post("/students/merge/preview")
async def preview_student_merge(request: Request, user=Depends(get_current_user)):
    """Preview what the merged student record will look like."""
    body = await request.json()
    primary_id = body.get("primary_id")
    secondary_id = body.get("secondary_id")
    
    primary = await db.students.find_one({"id": primary_id}, {"_id": 0})
    secondary = await db.students.find_one({"id": secondary_id}, {"_id": 0})
    if not primary or not secondary:
        raise HTTPException(404, "One or both students not found")
    
    # Build merged data — primary wins for same fields, secondary fills gaps
    merged = {**primary}
    secondary_fields = {}
    
    # Core fields — primary overwrites, track secondary differences
    for field in ["full_name", "phone", "email", "country", "city"]:
        p_val = primary.get(field)
        s_val = secondary.get(field)
        if p_val and s_val and str(p_val).strip().lower() != str(s_val).strip().lower():
            sec_key = f"secondary_{field}" if field in ["full_name", "phone"] else f"additional_{field}"
            secondary_fields[sec_key] = s_val
        elif not p_val and s_val:
            merged[field] = s_val
    
    # Numeric fields — take the higher/non-zero value
    for field in ["classes_attended", "enrollment_amount", "upgrade_count"]:
        p_val = primary.get(field) or 0
        s_val = secondary.get(field) or 0
        merged[field] = max(p_val, s_val)
    
    # Boolean fields — True if either is True
    for field in ["onboarding_complete", "upgrade_eligible", "is_upgraded_student"]:
        merged[field] = primary.get(field, False) or secondary.get(field, False)
    
    # Text fields — keep primary, fill from secondary if missing
    for field in ["student_code", "package_bought", "current_course_name", "mentor_name", "mentor_employee_id", "bd_agent_name", "bd_agent_id", "source"]:
        if not merged.get(field) and secondary.get(field):
            merged[field] = secondary.get(field)
    
    # Merge upgrade_history arrays
    p_history = primary.get("upgrade_history") or []
    s_history = secondary.get("upgrade_history") or []
    merged["upgrade_history"] = p_history + s_history
    
    # Add secondary fields
    merged.update(secondary_fields)
    
    # Get LTV transactions from both
    p_ltv = await db.ltv_transactions.find({"student_id": primary_id}, {"_id": 0}).to_list(100)
    s_ltv = await db.ltv_transactions.find({"student_id": secondary_id}, {"_id": 0}).to_list(100)
    
    # Get cs_upgrades from both
    p_cs = await db.cs_upgrades.find({"student_id": primary_id}, {"_id": 0}).to_list(100)
    s_cs = await db.cs_upgrades.find({"student_id": secondary_id}, {"_id": 0}).to_list(100)
    
    # Get notes from both
    p_notes = await db.student_notes.find({"student_id": primary_id}, {"_id": 0}).to_list(100)
    s_notes = await db.student_notes.find({"student_id": secondary_id}, {"_id": 0}).to_list(100)
    
    return {
        "primary": primary,
        "secondary": secondary,
        "merged_preview": merged,
        "secondary_fields_added": secondary_fields,
        "transactions_summary": {
            "primary_ltv": len(p_ltv),
            "secondary_ltv": len(s_ltv),
            "total_ltv": len(p_ltv) + len(s_ltv),
            "primary_upgrades": len(p_cs),
            "secondary_upgrades": len(s_cs),
            "total_upgrades": len(p_cs) + len(s_cs),
            "primary_notes": len(p_notes),
            "secondary_notes": len(s_notes),
            "total_notes": len(p_notes) + len(s_notes),
        }
    }


@api_router.post("/students/merge/request")
async def create_merge_request(request: Request, user=Depends(get_current_user)):
    """Create a merge request pending approval."""
    body = await request.json()
    primary_id = body.get("primary_id")
    secondary_id = body.get("secondary_id")
    merged_data = body.get("merged_data", {})
    
    primary = await db.students.find_one({"id": primary_id}, {"_id": 0, "id": 1, "full_name": 1})
    secondary = await db.students.find_one({"id": secondary_id}, {"_id": 0, "id": 1, "full_name": 1})
    if not primary or not secondary:
        raise HTTPException(404, "One or both students not found")
    
    # Check for existing pending merge
    existing = await db.merge_requests.find_one({
        "$or": [
            {"primary_student_id": primary_id, "secondary_student_id": secondary_id},
            {"primary_student_id": secondary_id, "secondary_student_id": primary_id},
        ],
        "status": {"$in": ["pending_cs_head", "pending_ceo"]}
    })
    if existing:
        raise HTTPException(409, "A merge request already exists for these students")
    
    now = datetime.now(timezone.utc).isoformat()
    merge_req = {
        "id": str(uuid.uuid4()),
        "primary_student_id": primary_id,
        "primary_student_name": primary["full_name"],
        "secondary_student_id": secondary_id,
        "secondary_student_name": secondary["full_name"],
        "merged_data_preview": merged_data,
        "status": "pending_cs_head",
        "requested_by": user["id"],
        "requested_by_name": user.get("full_name", ""),
        "requested_at": now,
        "cs_head_approved_by": None,
        "cs_head_approved_at": None,
        "ceo_approved_by": None,
        "ceo_approved_at": None,
        "rejected_by": None,
        "rejected_at": None,
        "rejection_reason": None,
        "executed_at": None,
        "created_at": now,
    }
    await db.merge_requests.insert_one(merge_req)
    
    # Notify CS heads
    cs_heads = await db.users.find({"role": {"$in": ["cs_head", "super_admin"]}, "is_active": True}, {"_id": 0, "id": 1}).to_list(20)
    for head in cs_heads:
        await db.notifications.insert_one({
            "id": str(uuid.uuid4()),
            "user_id": head["id"],
            "title": "Student Merge Request",
            "message": f"{user.get('full_name', 'Agent')} requested to merge '{secondary['full_name']}' into '{primary['full_name']}'",
            "type": "merge_request",
            "reference_id": merge_req["id"],
            "read": False,
            "created_at": now,
        })
    
    merge_req.pop("_id", None)
    return merge_req


@api_router.get("/students/merge/requests")
async def get_merge_requests(status: str = None, user=Depends(get_current_user)):
    """Get merge requests. CS Head sees pending_cs_head, CEO sees pending_ceo, admins see all."""
    query = {}
    if status:
        query["status"] = status
    elif user["role"] == "cs_head":
        query["status"] = {"$in": ["pending_cs_head", "pending_ceo", "approved", "rejected"]}
    elif user["role"] == "super_admin":
        pass  # see all
    else:
        query["requested_by"] = user["id"]
    
    requests = await db.merge_requests.find(query, {"_id": 0}).sort("created_at", -1).to_list(50)
    return requests


@api_router.post("/students/merge/{request_id}/approve")
async def approve_merge_request(request_id: str, request: Request, user=Depends(get_current_user)):
    """Approve a merge request. CS Head first, then CEO."""
    merge_req = await db.merge_requests.find_one({"id": request_id}, {"_id": 0})
    if not merge_req:
        raise HTTPException(404, "Merge request not found")
    
    now = datetime.now(timezone.utc).isoformat()
    
    if merge_req["status"] == "pending_cs_head":
        if user["role"] not in ["cs_head", "super_admin"]:
            raise HTTPException(403, "Only CS Head or Super Admin can approve at this stage")
        await db.merge_requests.update_one({"id": request_id}, {"$set": {
            "status": "pending_ceo",
            "cs_head_approved_by": user["id"],
            "cs_head_approved_by_name": user.get("full_name", ""),
            "cs_head_approved_at": now,
        }})
        # Notify CEO
        ceos = await db.users.find({"role": "super_admin", "is_active": True}, {"_id": 0, "id": 1}).to_list(5)
        for ceo in ceos:
            await db.notifications.insert_one({
                "id": str(uuid.uuid4()),
                "user_id": ceo["id"],
                "title": "Merge Awaiting Final Approval",
                "message": f"CS Head approved merge of '{merge_req['secondary_student_name']}' into '{merge_req['primary_student_name']}'. Your approval needed.",
                "type": "merge_request",
                "reference_id": request_id,
                "read": False,
                "created_at": now,
            })
        return {"status": "pending_ceo", "message": "Approved by CS Head. Awaiting CEO approval."}
    
    elif merge_req["status"] == "pending_ceo":
        if user["role"] != "super_admin":
            raise HTTPException(403, "Only Super Admin / CEO can give final approval")
        
        # Execute the merge
        primary_id = merge_req["primary_student_id"]
        secondary_id = merge_req["secondary_student_id"]
        merged_data = merge_req.get("merged_data_preview", {})
        
        # Remove fields that shouldn't be updated
        for key in ["id", "lead_id", "created_at", "match_score", "match_reasons"]:
            merged_data.pop(key, None)
        merged_data["updated_at"] = now
        
        # 1. Update primary student with merged data
        await db.students.update_one({"id": primary_id}, {"$set": merged_data})
        
        # 2. Move secondary's ltv_transactions to primary
        await db.ltv_transactions.update_many(
            {"student_id": secondary_id},
            {"$set": {"student_id": primary_id, "merged_from": secondary_id}}
        )
        
        # 3. Move secondary's cs_upgrades to primary
        await db.cs_upgrades.update_many(
            {"student_id": secondary_id},
            {"$set": {"student_id": primary_id, "merged_from": secondary_id}}
        )
        
        # 4. Move secondary's notes to primary
        await db.student_notes.update_many(
            {"student_id": secondary_id},
            {"$set": {"student_id": primary_id, "merged_from": secondary_id}}
        )
        
        # 5. Move reminders
        await db.reminders.update_many(
            {"entity_id": secondary_id},
            {"$set": {"entity_id": primary_id, "merged_from": secondary_id}}
        )
        
        # 6. Move finance verifications
        await db.finance_verifications.update_many(
            {"student_id": secondary_id},
            {"$set": {"student_id": primary_id, "merged_from": secondary_id}}
        )
        
        # 7. Move cs_commissions
        await db.cs_commissions.update_many(
            {"student_id": secondary_id},
            {"$set": {"student_id": primary_id, "merged_from": secondary_id}}
        )
        
        # 8. Soft-delete secondary student
        await db.students.update_one({"id": secondary_id}, {"$set": {
            "merged_into": primary_id,
            "merged_at": now,
            "stage": "merged",
            "original_stage": merge_req.get("secondary_student_name"),
        }})
        
        # 9. Update merge request
        await db.merge_requests.update_one({"id": request_id}, {"$set": {
            "status": "approved",
            "ceo_approved_by": user["id"],
            "ceo_approved_by_name": user.get("full_name", ""),
            "ceo_approved_at": now,
            "executed_at": now,
        }})
        
        # 10. Notify requester
        await db.notifications.insert_one({
            "id": str(uuid.uuid4()),
            "user_id": merge_req["requested_by"],
            "title": "Merge Completed",
            "message": f"'{merge_req['secondary_student_name']}' has been merged into '{merge_req['primary_student_name']}'.",
            "type": "merge_complete",
            "reference_id": request_id,
            "read": False,
            "created_at": now,
        })
        
        return {"status": "approved", "message": "Merge executed successfully."}
    
    else:
        raise HTTPException(400, f"Cannot approve request with status '{merge_req['status']}'")


@api_router.post("/students/merge/{request_id}/reject")
async def reject_merge_request(request_id: str, request: Request, user=Depends(get_current_user)):
    """Reject a merge request."""
    body = await request.json()
    reason = body.get("reason", "")
    
    merge_req = await db.merge_requests.find_one({"id": request_id})
    if not merge_req:
        raise HTTPException(404, "Merge request not found")
    if merge_req["status"] not in ["pending_cs_head", "pending_ceo"]:
        raise HTTPException(400, "Cannot reject this request")
    
    now = datetime.now(timezone.utc).isoformat()
    await db.merge_requests.update_one({"id": request_id}, {"$set": {
        "status": "rejected",
        "rejected_by": user["id"],
        "rejected_by_name": user.get("full_name", ""),
        "rejected_at": now,
        "rejection_reason": reason,
    }})
    
    # Notify requester
    await db.notifications.insert_one({
        "id": str(uuid.uuid4()),
        "user_id": merge_req["requested_by"],
        "title": "Merge Request Rejected",
        "message": f"Merge of '{merge_req['secondary_student_name']}' into '{merge_req['primary_student_name']}' was rejected. {reason}",
        "type": "merge_rejected",
        "reference_id": request_id,
        "read": False,
        "created_at": now,
    })
    
    return {"status": "rejected", "message": "Merge request rejected."}



# ==================== COMMISSION DASHBOARD SYSTEM ====================

SALES_BENCHMARK_AED = 18000  # Sales agents earn 0 until they hit this monthly revenue

_course_catalog_cache = {"data": None, "ts": 0}

async def _get_course_catalog():
    """Cached course catalog loader - refreshes every 60s."""
    now = _time.time()
    if _course_catalog_cache["data"] is None or now - _course_catalog_cache["ts"] > 60:
        _course_catalog_cache["data"] = await db.course_catalog.find({"is_active": True}, {"_id": 0}).to_list(100)
        _course_catalog_cache["ts"] = now
    return _course_catalog_cache["data"]


async def _match_course_commission(amount: float, course_type: str = "course"):
    """Match enrollment amount to course(s) in course_catalog.
    
    Handles composite enrollments (e.g. Course + Addon Pack):
    1. Try exact single-item match
    2. Try decomposing as Course + Addon (sum of commissions)
    3. Fallback to closest single course within 15%
    """
    full_catalog = await _get_course_catalog()
    catalog = [c for c in full_catalog if c.get("type") in ([course_type, "addon"] if course_type == "course" else [course_type])]
    if not catalog:
        return {}

    courses = [c for c in catalog if c.get("type") != "addon"]
    addons = [c for c in catalog if c.get("type") == "addon"]
    comm_fields = [
        "commission_sales_executive", "commission_team_leader",
        "commission_sales_manager", "commission_cs_agent",
        "commission_cs_head", "commission_mentor",
    ]

    # 1. Exact single-item match (course or addon)
    for c in catalog:
        if c.get("price") == amount:
            return c

    # 2. Decompose as Course + Addon
    tolerance = 20  # AED tolerance for rounding
    best = None
    best_diff = tolerance + 1
    for course in courses:
        residual = amount - (course.get("price") or 0)
        if residual <= 0:
            continue
        for addon in addons:
            diff = abs(residual - (addon.get("price") or 0))
            if diff <= tolerance and diff < best_diff:
                combined = {
                    "name": f"{course.get('name')} + {addon.get('name')}",
                    "price": amount,
                    "type": course_type,
                }
                for f in comm_fields:
                    combined[f] = (course.get(f) or 0) + (addon.get(f) or 0)
                best = combined
                best_diff = diff

    if best:
        return best

    # 3. Fallback: closest single course within 15%
    closest = min(courses or catalog, key=lambda c: abs((c.get("price") or 0) - amount))
    if abs((closest.get("price") or 0) - amount) <= amount * 0.15:
        return closest
    return {}


async def _calc_sales_commissions(agent_id: str, month: str):
    """Calculate sales commissions for an agent for a given month (YYYY-MM).
    
    TL/SM: No 18K benchmark — commissions always earned.
    SE: Must cross 18K AED revenue to unlock commissions.
    """
    month_start = f"{month}-01"
    month_end = f"{month}-31"

    # Get agent role to determine benchmark rule
    agent_user = await db.users.find_one({"id": agent_id}, {"_id": 0, "role": 1})
    agent_role = agent_user.get("role", "sales_executive") if agent_user else "sales_executive"
    is_tl_or_sm = agent_role in ("team_leader", "sales_manager")

    # Get all enrolled leads for this agent this month
    enrolled = await db.leads.find({
        "assigned_to": agent_id,
        "stage": "enrolled",
        "enrolled_at": {"$gte": month_start, "$lte": month_end + "T23:59:59"},
    }, {"_id": 0, "id": 1, "full_name": 1, "enrollment_amount": 1, "sale_amount": 1, "course_name": 1, "enrolled_at": 1}).to_list(500)

    total_revenue = sum((l.get("enrollment_amount") or l.get("sale_amount") or 0) for l in enrolled)
    benchmark_crossed = total_revenue >= SALES_BENCHMARK_AED

    earned_details = []
    for lead in enrolled:
        amt = lead.get("enrollment_amount") or lead.get("sale_amount") or 0
        course = await _match_course_commission(amt, "course")
        se_comm = course.get("commission_sales_executive", 0)
        tl_comm = course.get("commission_team_leader", 0)
        sm_comm = course.get("commission_sales_manager", 0)
        earned_details.append({
            "lead_name": lead.get("full_name"),
            "amount": amt,
            "course_matched": course.get("name", "Unknown"),
            "se_commission": se_comm,
            "tl_commission": tl_comm,
            "sm_commission": sm_comm,
            "date": str(lead.get("enrolled_at", ""))[:10],
        })

    total_se = sum(d["se_commission"] for d in earned_details)
    total_tl = sum(d["tl_commission"] for d in earned_details)
    total_sm = sum(d["sm_commission"] for d in earned_details)

    # For TL/SM: also calculate TL commission from team members' deals
    team_tl_earned = 0
    team_tl_details = []
    if is_tl_or_sm:
        team_members = await db.users.find(
            {"team_leader_id": agent_id, "role": "sales_executive", "is_active": True},
            {"_id": 0, "id": 1, "full_name": 1}
        ).to_list(50)
        for member in team_members:
            member_enrolled = await db.leads.find({
                "assigned_to": member["id"],
                "stage": "enrolled",
                "enrolled_at": {"$gte": month_start, "$lte": month_end},
            }, {"_id": 0, "full_name": 1, "enrollment_amount": 1, "sale_amount": 1, "enrolled_at": 1}).to_list(200)
            for lead in member_enrolled:
                amt = lead.get("enrollment_amount") or lead.get("sale_amount") or 0
                course = await _match_course_commission(amt, "course")
                tl_comm = course.get("commission_team_leader", 0)
                if tl_comm > 0:
                    team_tl_earned += tl_comm
                    team_tl_details.append({
                        "lead_name": lead.get("full_name"),
                        "agent_name": member["full_name"],
                        "amount": amt,
                        "course_matched": course.get("name", "Unknown"),
                        "tl_commission": tl_comm,
                        "date": str(lead.get("enrolled_at", ""))[:10],
                    })

    # Pipeline (pending) — leads in hot_lead, in_progress, warm_lead stages
    pipeline_leads = await db.leads.find({
        "assigned_to": agent_id,
        "stage": {"$in": ["hot_lead", "in_progress", "warm_lead"]},
    }, {"_id": 0, "id": 1, "full_name": 1, "estimated_value": 1, "enrollment_amount": 1, "course_name": 1, "course_of_interest": 1, "stage": 1}).to_list(200)

    pipeline_details = []
    for lead in pipeline_leads:
        est = lead.get("estimated_value") or lead.get("enrollment_amount") or 0
        if est > 0:
            course = await _match_course_commission(est, "course")
            pipeline_details.append({
                "lead_name": lead.get("full_name"),
                "amount": est,
                "course_matched": course.get("name", "Unknown"),
                "se_commission": course.get("commission_sales_executive", 0),
                "tl_commission": course.get("commission_team_leader", 0),
                "sm_commission": course.get("commission_sales_manager", 0),
                "stage": lead.get("stage"),
            })

    pending_se = sum(d["se_commission"] for d in pipeline_details)
    pending_tl = sum(d["tl_commission"] for d in pipeline_details)

    # For TL/SM: no benchmark needed — commissions always earned
    # For SE: must cross 18K to earn, otherwise pending
    se_earned = total_se if (is_tl_or_sm or benchmark_crossed) else 0
    se_pending = (pending_se + (total_se if not (is_tl_or_sm or benchmark_crossed) else 0))

    return {
        "agent_id": agent_id,
        "month": month,
        "total_revenue": total_revenue,
        "benchmark": SALES_BENCHMARK_AED,
        "benchmark_crossed": benchmark_crossed,
        "is_tl_or_sm": is_tl_or_sm,
        "earned_commission": se_earned,
        "pending_commission": se_pending,
        "earned_tl": total_tl + team_tl_earned,  # Own deals TL + team members TL
        "pending_tl": pending_tl,
        "sm_pool": total_sm,
        "earned_details": earned_details,
        "team_tl_details": team_tl_details,
        "pipeline_details": pipeline_details,
        "deals_closed": len(enrolled),
        "pipeline_count": len(pipeline_details),
    }


async def _calc_cs_commissions(agent_id: str, agent_name: str, month: str):
    """Calculate CS commissions for an agent for a given month."""
    month_start = f"{month}-01"
    month_end = f"{month}-31"

    # Earned: closed upgrades this month
    upgrades = await db.cs_upgrades.find({
        "cs_agent_id": agent_id,
        "date": {"$gte": month_start, "$lte": month_end},
    }, {"_id": 0}).to_list(200)

    earned_details = []
    for u in upgrades:
        amt = u.get("amount") or u.get("course_amount") or 0
        course = await _match_course_commission(amt, "upgrade")
        earned_details.append({
            "student_name": u.get("student_name"),
            "amount": amt,
            "course_matched": course.get("name", "Unknown"),
            "cs_commission": course.get("commission_cs_agent", 0),
            "cs_head_commission": course.get("commission_cs_head", 0),
            "mentor_commission": course.get("commission_mentor", 0),
            "date": u.get("date"),
        })

    total_cs = sum(d["cs_commission"] for d in earned_details)
    total_csh = sum(d["cs_head_commission"] for d in earned_details)
    total_mentor = sum(d["mentor_commission"] for d in earned_details)

    # Pending: students in pitched_for_upgrade, in_progress, interested stages
    pipeline_students = await db.students.find({
        "cs_agent_id": agent_id,
        "stage": {"$in": ["pitched_for_upgrade", "in_progress", "interested"]},
        "pitched_upgrade_price": {"$exists": True, "$gt": 0},
    }, {"_id": 0, "id": 1, "full_name": 1, "pitched_upgrade_price": 1, "pitched_upgrade_path": 1, "stage": 1}).to_list(200)

    pipeline_details = []
    for s in pipeline_students:
        amt = s.get("pitched_upgrade_price", 0)
        course = await _match_course_commission(amt, "upgrade")
        pipeline_details.append({
            "student_name": s.get("full_name"),
            "amount": amt,
            "course_matched": course.get("name", "Unknown"),
            "cs_commission": course.get("commission_cs_agent", 0),
            "cs_head_commission": course.get("commission_cs_head", 0),
            "mentor_commission": course.get("commission_mentor", 0),
            "stage": s.get("stage"),
        })

    pending_cs = sum(d["cs_commission"] for d in pipeline_details)
    pending_csh = sum(d["cs_head_commission"] for d in pipeline_details)
    pending_mentor = sum(d["mentor_commission"] for d in pipeline_details)

    return {
        "agent_id": agent_id,
        "agent_name": agent_name,
        "month": month,
        "earned_commission": total_cs,
        "pending_commission": pending_cs,
        "earned_cs_head": total_csh,
        "pending_cs_head": pending_csh,
        "earned_mentor": total_mentor,
        "pending_mentor": pending_mentor,
        "earned_details": earned_details,
        "pipeline_details": pipeline_details,
        "upgrades_closed": len(upgrades),
        "pipeline_count": len(pipeline_details),
    }


@api_router.get("/commissions/dashboard")
async def get_commission_dashboard(month: str = None, user=Depends(get_current_user)):
    """Main commission dashboard — returns data based on user's role."""
    if not month:
        month = datetime.now(timezone.utc).strftime("%Y-%m")

    role = user["role"]
    result = {"month": month, "role": role}

    if role in ["sales_executive", "team_leader"]:
        # My commissions
        my_comm = await _calc_sales_commissions(user["id"], month)
        result["my_commission"] = my_comm

        if role == "team_leader":
            # Team commissions
            team = await db.teams.find_one({"leader_id": user["id"]}, {"_id": 0, "id": 1})
            if team:
                members = await db.users.find(
                    {"team_id": team["id"], "role": "sales_executive", "is_active": True},
                    {"_id": 0, "id": 1, "full_name": 1}
                ).to_list(50)
                team_data = []
                for m in members:
                    mc = await _calc_sales_commissions(m["id"], month)
                    mc["agent_name"] = m["full_name"]
                    team_data.append(mc)
                result["team_commissions"] = team_data
                result["team_total_earned"] = sum(t["earned_commission"] for t in team_data)
                result["team_total_pending"] = sum(t["pending_commission"] for t in team_data)
                # TL earns TL commission from all team members' deals
                result["my_tl_earned"] = my_comm["earned_tl"] + sum(t["earned_tl"] for t in team_data)
                result["my_tl_pending"] = my_comm["pending_tl"] + sum(t["pending_tl"] for t in team_data)

    elif role in ["cs_agent", "cs_head"]:
        my_comm = await _calc_cs_commissions(user["id"], user.get("full_name", ""), month)
        result["my_commission"] = my_comm

        if role == "cs_head":
            agents = await db.users.find(
                {"role": "cs_agent", "is_active": True},
                {"_id": 0, "id": 1, "full_name": 1}
            ).to_list(50)
            team_data = []
            for a in agents:
                ac = await _calc_cs_commissions(a["id"], a["full_name"], month)
                team_data.append(ac)
            result["team_commissions"] = team_data
            result["total_cs_head_earned"] = my_comm["earned_cs_head"] + sum(t["earned_cs_head"] for t in team_data)
            result["total_cs_head_pending"] = my_comm["pending_cs_head"] + sum(t["pending_cs_head"] for t in team_data)

    elif role == "super_admin":
        # CEO: see everything — parallelize agent calculations
        sales_agents = await db.users.find(
            {"role": {"$in": ["sales_executive", "team_leader"]}, "is_active": True},
            {"_id": 0, "id": 1, "full_name": 1, "role": 1}
        ).to_list(100)
        cs_agents = await db.users.find(
            {"role": {"$in": ["cs_agent", "cs_head"]}, "is_active": True},
            {"_id": 0, "id": 1, "full_name": 1, "role": 1}
        ).to_list(50)

        sales_tasks = [_calc_sales_commissions(a["id"], month) for a in sales_agents]
        cs_tasks = [_calc_cs_commissions(a["id"], a["full_name"], month) for a in cs_agents]
        all_results = await asyncio.gather(*sales_tasks, *cs_tasks)

        sales_results = all_results[:len(sales_agents)]
        cs_results = all_results[len(sales_agents):]

        sales_data = []
        for i, a in enumerate(sales_agents):
            sc = sales_results[i]
            sc["agent_name"] = a["full_name"]
            sc["agent_role"] = a["role"]
            sales_data.append(sc)

        result["sales_commissions"] = sales_data
        result["total_sales_earned"] = sum(s["earned_commission"] for s in sales_data)
        result["total_sales_pending"] = sum(s["pending_commission"] for s in sales_data)
        # Only sum TL rows for total TL earned (SE rows are informational — already included in TL rows)
        result["total_tl_earned"] = sum(s["earned_tl"] for s in sales_data if s.get("is_tl_or_sm"))
        result["total_tl_pending"] = sum(s["pending_tl"] for s in sales_data if s.get("is_tl_or_sm"))
        result["sm_bonus_pool"] = sum(s["sm_pool"] for s in sales_data)

        cs_data = []
        for i, a in enumerate(cs_agents):
            cc = cs_results[i]
            cc["agent_role"] = a["role"]
            cs_data.append(cc)

        result["cs_commissions"] = cs_data
        result["total_cs_earned"] = sum(c["earned_commission"] for c in cs_data)
        result["total_cs_pending"] = sum(c["pending_commission"] for c in cs_data)
        result["total_cs_head_earned"] = sum(c["earned_cs_head"] for c in cs_data)
        result["mentor_pool"] = sum(c["earned_mentor"] + c["pending_mentor"] for c in cs_data)

        # Include approval status for CEO view
        approvals = await db.commission_approvals.find({"month": month}, {"_id": 0}).to_list(10)
        result["approvals"] = {a["department"]: {"status": a["status"], "approved_by": a.get("approved_by_name", ""), "approved_at": a.get("approved_at", "")} for a in approvals}

    # For non-CEO: include their department's approval status
    if role not in ["super_admin"]:
        dept = "sales" if role in ["sales_executive", "team_leader"] else "cs" if role in ["cs_agent", "cs_head"] else None
        if dept:
            approval = await db.commission_approvals.find_one({"month": month, "department": dept}, {"_id": 0})
            result["approval_status"] = approval["status"] if approval else "pending"

    return result


@api_router.get("/commissions/scatter-data")
async def get_commission_scatter_data(user_id: str = None, months: int = 6, user=Depends(get_current_user)):
    """XY scatter data: months horizontal, commission + net pay lines."""
    target_id = user_id or user["id"]
    target_user = await db.users.find_one({"id": target_id}, {"_id": 0, "id": 1, "full_name": 1, "role": 1})
    if not target_user:
        raise HTTPException(404, "User not found")

    # Get salary from HR
    emp = await db.hr_employees.find_one({"user_id": target_id}, {"_id": 0, "basic_salary": 1, "salary_structure": 1})
    base_salary = 0
    if emp:
        ss = emp.get("salary_structure") or {}
        base_salary = ss.get("gross_salary") or ss.get("net_salary") or emp.get("basic_salary", 0)

    now = datetime.now(timezone.utc)
    data_points = []
    is_sales = target_user["role"] in ["sales_executive", "team_leader"]

    month_ranges = []
    for i in range(months - 1, -1, -1):
        dt = now - timedelta(days=i * 30)
        month_ranges.append((dt.strftime("%Y-%m"), dt.strftime("%b %Y")))

    if is_sales:
        tasks = [_calc_sales_commissions(target_id, mr[0]) for mr in month_ranges]
    else:
        tasks = [_calc_cs_commissions(target_id, target_user["full_name"], mr[0]) for mr in month_ranges]
    results = await asyncio.gather(*tasks)

    data_points = []
    for idx, (m, m_label) in enumerate(month_ranges):
        comm = results[idx]
        earned = comm["earned_commission"]
        if is_sales and target_user["role"] == "team_leader":
            earned += comm.get("earned_tl", 0)
        data_points.append({
            "month": m,
            "label": m_label,
            "commission": earned,
            "net_pay": base_salary + earned,
            "base_salary": base_salary,
        })

    return {
        "agent_name": target_user["full_name"],
        "role": target_user["role"],
        "base_salary": base_salary,
        "data": data_points,
    }


