@api_router.put("/mt5/link-student")
async def link_student_mt5(data: dict = Body(...), user=Depends(get_current_user)):
    """Link a student to an MT5 account number. Admin/CS only."""
    if user["role"] not in ADMIN_CS_ROLES:
        raise HTTPException(403, "Not authorized")
    student_id = data.get("student_id")
    mt5_account = data.get("mt5_account_number", "").strip()
    if not student_id or not mt5_account:
        raise HTTPException(400, "student_id and mt5_account_number required")
    # Debug: verify the student_id
    logger.info(f"MT5 link attempt: student_id='{student_id}' type={type(student_id).__name__} mt5={mt5_account}")
    results = await db.students.find({"id": student_id}, {"_id": 0, "id": 1, "mt5_account_number": 1, "mt5_account_history": 1}).to_list(1)
    student = results[0] if results else None
    if not student or not student.get("id"):
        raise HTTPException(404, "Student not found")
    # Check for duplicate MT5 account
    existing = await db.students.find_one({"mt5_account_number": mt5_account, "id": {"$ne": student_id}}, {"_id": 0, "id": 1, "full_name": 1})
    if existing:
        raise HTTPException(400, f"MT5 account {mt5_account} already linked to {existing.get('full_name')}")
    # Update MT5 account and history
    now_iso = datetime.now(timezone.utc).isoformat()
    history = student.get("mt5_account_history") or []
    old_mt5 = student.get("mt5_account_number")
    if old_mt5:
        for h in history:
            if h.get("account_number") == old_mt5:
                h["status"] = "previous"
    history.append({"account_number": mt5_account, "added_at": now_iso, "status": "active", "linked_by": user["full_name"]})
    await db.students.update_one({"id": student_id}, {"$set": {
        "mt5_account_number": mt5_account,
        "mt5_account_history": history,
        "updated_at": now_iso
    }})
    return {"success": True, "message": f"MT5 account {mt5_account} linked successfully"}

@api_router.put("/mt5/unlink-student")
async def unlink_student_mt5(data: dict = Body(...), user=Depends(get_current_user)):
    """Unlink a student's MT5 account. Admin/CS only."""
    if user["role"] not in ADMIN_CS_ROLES:
        raise HTTPException(403, "Not authorized")
    student_id = data.get("student_id")
    if not student_id:
        raise HTTPException(400, "student_id required")
    results = await db.students.find({"id": student_id}, {"_id": 0, "id": 1, "mt5_account_number": 1, "mt5_account_history": 1}).to_list(1)
    student = results[0] if results else None
    if not student or not student.get("id"):
        raise HTTPException(404, "Student not found")
    now_iso = datetime.now(timezone.utc).isoformat()
    history = student.get("mt5_account_history") or []
    old_mt5 = student.get("mt5_account_number")
    if old_mt5:
        for h in history:
            if h.get("account_number") == old_mt5:
                h["status"] = "unlinked"
                h["unlinked_at"] = now_iso
    await db.students.update_one({"id": student_id}, {"$set": {
        "mt5_account_number": None,
        "mt5_account_history": history,
        "updated_at": now_iso
    }})
    return {"success": True, "message": "MT5 account unlinked"}

@api_router.post("/mt5/sync")
async def trigger_mt5_sync(data: dict = Body(default={}), user=Depends(get_current_user)):
    """Manually trigger MT5 withdrawal sync. Admin/CS only."""
    if user["role"] not in ADMIN_CS_ROLES:
        raise HTTPException(403, "Not authorized")
    result = await _run_mt5_withdrawal_sync(triggered_by=user["full_name"])
    return result

@api_router.get("/mt5/sync-logs")
async def get_mt5_sync_logs(limit: int = 20, user=Depends(get_current_user)):
    """Get MT5 sync history logs."""
    if user["role"] not in ADMIN_CS_ROLES:
        raise HTTPException(403, "Not authorized")
    logs = await db.mt5_sync_logs.find({}, {"_id": 0}).sort("synced_at", -1).limit(limit).to_list(limit)
    return {"logs": logs}

async def _run_mt5_withdrawal_sync(triggered_by="auto"):
    """Core sync logic: Pull withdrawals from MT5, match to students, create mentor_withdrawals."""
    USD_TO_AED = float(os.environ.get("USD_TO_AED_RATE", "3.674"))
    sync_log = {
        "id": str(uuid.uuid4()),
        "synced_at": datetime.now(timezone.utc).isoformat(),
        "triggered_by": triggered_by,
        "status": "running",
        "withdrawals_found": 0,
        "withdrawals_synced": 0,
        "withdrawals_skipped": 0,
        "errors": [],
        "details": []
    }

    try:
        client = MT5Client()
        ok, msg = client.connect()
        if not ok:
            sync_log["status"] = "auth_failed"
            sync_log["errors"].append(msg)
            await db.mt5_sync_logs.insert_one({**{k: v for k, v in sync_log.items()}, "_id": sync_log["id"]})
            return {k: v for k, v in sync_log.items() if k != "_id"}

        # Get all students with MT5 accounts
        linked_students = await db.students.find(
            {"mt5_account_number": {"$ne": None, "$exists": True, "$nin": ["", None]}},
            {"_id": 0, "id": 1, "full_name": 1, "email": 1, "mt5_account_number": 1, "mentor_id": 1, "mentor_name": 1}
        ).to_list(1000)

        if not linked_students:
            sync_log["status"] = "completed"
            sync_log["errors"].append("No students linked to MT5 accounts")
            await db.mt5_sync_logs.insert_one({k: v for k, v in sync_log.items() if k != "_id"})
            client.close()
            return sync_log

        # Time range: last 30 days
        now = datetime.now(timezone.utc)
        from_ts = int((now - timedelta(days=30)).timestamp())
        to_ts = int(now.timestamp())

        total_found = 0
        total_synced = 0
        total_skipped = 0

        for student in linked_students:
            mt5_account = student["mt5_account_number"]
            try:
                # Extract numeric login from MT5 account (e.g., "MT5_12345" -> "12345" or just "12345")
                mt5_login = mt5_account.replace("MT5_", "").replace("mt5_", "").strip()
                if not mt5_login.isdigit():
                    continue

                deals, deal_msg = client.get_deals(mt5_login, from_ts, to_ts)
                withdrawals = extract_withdrawals(deals)
                total_found += len(withdrawals)

                for w in withdrawals:
                    # Check if already synced (by MT5 ticket)
                    existing = await db.mentor_withdrawals.find_one({"mt5_ticket": w["ticket"]}, {"_id": 0, "id": 1})
                    if existing:
                        total_skipped += 1
                        continue

                    # Create withdrawal record
                    w_date = datetime.fromtimestamp(w["timestamp"], tz=timezone.utc)
                    withdrawal_doc = {
                        "id": str(uuid.uuid4()),
                        "date": w_date.strftime("%Y-%m-%d"),
                        "month": w_date.strftime("%Y-%m"),
                        "mentor_id": student.get("mentor_id", ""),
                        "mentor_name": student.get("mentor_name", ""),
                        "student_id": student["id"],
                        "student_name": student["full_name"],
                        "student_email": student.get("email", ""),
                        "amount": w["amount_usd"],
                        "amount_aed": round(w["amount_usd"] * USD_TO_AED, 2),
                        "mt5_ticket": w["ticket"],
                        "mt5_account": mt5_account,
                        "mt5_comment": w.get("comment", ""),
                        "notes": f"Auto-synced from MT5 (ticket: {w['ticket']})",
                        "source": "mt5_sync",
                        "created_at": now.isoformat(),
                        "created_by": "mt5_sync"
                    }
                    await db.mentor_withdrawals.insert_one({k: v for k, v in withdrawal_doc.items() if k != "_id"})
                    total_synced += 1
                    sync_log["details"].append({
                        "student": student["full_name"],
                        "mt5_account": mt5_account,
                        "amount_usd": w["amount_usd"],
                        "date": w_date.strftime("%Y-%m-%d"),
                        "ticket": w["ticket"]
                    })

            except Exception as e:
                sync_log["errors"].append(f"Error processing {student['full_name']} ({mt5_account}): {str(e)}")

        sync_log["status"] = "completed"
        sync_log["withdrawals_found"] = total_found
        sync_log["withdrawals_synced"] = total_synced
        sync_log["withdrawals_skipped"] = total_skipped
        client.close()

    except Exception as e:
        sync_log["status"] = "error"
        sync_log["errors"].append(str(e))
        logger.error(f"MT5 sync error: {e}")

    await db.mt5_sync_logs.insert_one({**{k: v for k, v in sync_log.items()}, "_id": sync_log["id"]})
    return {k: v for k, v in sync_log.items() if k != "_id"}


# ======================== INTERNAL CHAT SYSTEM ========================

@api_router.get("/chat/conversations")
async def get_chat_conversations(user=Depends(get_current_user)):
    """Get all conversations for the current user."""
    user_id = user["id"]
    convos = await db.chat_conversations.find(
        {"participants": user_id},
        {"_id": 0}
    ).sort("last_message_at", -1).to_list(100)
    
    # Enrich with participant names and unread counts
    all_user_ids = set()
    for c in convos:
        all_user_ids.update(c.get("participants", []))
    
    user_map = {}
    if all_user_ids:
        now = datetime.now(timezone.utc)
        async for u in db.users.find({"id": {"$in": list(all_user_ids)}}, {"_id": 0, "id": 1, "full_name": 1, "role": 1, "department": 1, "last_active": 1}):
            la = u.get("last_active")
            if la:
                try:
                    last = datetime.fromisoformat(la.replace("Z", "+00:00"))
                    diff_minutes = (now - last).total_seconds() / 60
                    u["status"] = "online" if diff_minutes < 10 else "away" if diff_minutes < 60 else "offline"
                except Exception:
                    u["status"] = "offline"
            else:
                u["status"] = "offline"
            user_map[u["id"]] = u
    
    result = []
    for c in convos:
        is_group = c.get("is_group", False)
        other_participants = [user_map.get(p, {"id": p, "full_name": "Unknown"}) for p in c["participants"] if p != user_id]
        unread = await db.chat_messages.count_documents({
            "conversation_id": c["id"],
            "sender_id": {"$ne": user_id},
            "read_by": {"$nin": [user_id]}
        })
        result.append({
            **c,
            "display_name": c.get("group_name") if is_group else (other_participants[0]["full_name"] if other_participants else "Unknown"),
            "other_participants": other_participants,
            "unread_count": unread,
        })
    return result


@api_router.post("/chat/conversations")
async def create_conversation(data: dict = Body(...), user=Depends(get_current_user)):
    """Create a new DM or group conversation."""
    user_id = user["id"]
    participant_ids = data.get("participant_ids", [])
    is_group = data.get("is_group", False)
    group_name = data.get("group_name", "")
    
    if not participant_ids:
        raise HTTPException(400, "At least one participant required")
    
    all_participants = list(set([user_id] + participant_ids))
    
    # For DMs, check if conversation already exists
    if not is_group and len(all_participants) == 2:
        existing = await db.chat_conversations.find_one({
            "is_group": False,
            "participants": {"$all": all_participants, "$size": 2}
        }, {"_id": 0})
        if existing:
            return existing
    
    now = datetime.now(timezone.utc).isoformat()
    convo = {
        "id": str(uuid.uuid4()),
        "participants": all_participants,
        "is_group": is_group,
        "group_name": group_name if is_group else "",
        "created_by": user_id,
        "created_at": now,
        "last_message_at": now,
        "last_message_preview": "",
    }
    await db.chat_conversations.insert_one(convo)
    convo.pop("_id", None)
    return convo


@api_router.get("/chat/conversations/{conversation_id}/messages")
async def get_chat_messages(conversation_id: str, limit: int = 50, before: str = None, user=Depends(get_current_user)):
    """Get messages for a conversation."""
    convo = await db.chat_conversations.find_one({"id": conversation_id}, {"_id": 0})
    if not convo or user["id"] not in convo.get("participants", []):
        raise HTTPException(403, "Access denied")
    
    query = {"conversation_id": conversation_id}
    if before:
        query["created_at"] = {"$lt": before}
    
    messages = await db.chat_messages.find(
        query, {"_id": 0}
    ).sort("created_at", -1).limit(limit).to_list(limit)
    
    messages.reverse()
    
    # Mark messages as read
    await db.chat_messages.update_many(
        {"conversation_id": conversation_id, "sender_id": {"$ne": user["id"]}, "read_by": {"$nin": [user["id"]]}},
        {"$addToSet": {"read_by": user["id"]}}
    )
    
    return {"messages": messages, "conversation": convo}


@api_router.post("/chat/conversations/{conversation_id}/messages")
async def send_chat_message(conversation_id: str, data: dict = Body(...), user=Depends(get_current_user)):
    """Send a message in a conversation."""
    convo = await db.chat_conversations.find_one({"id": conversation_id}, {"_id": 0})
    if not convo or user["id"] not in convo.get("participants", []):
        raise HTTPException(403, "Access denied")
    
    text = data.get("text", "").strip()
    if not text:
        raise HTTPException(400, "Message cannot be empty")
    
    now = datetime.now(timezone.utc).isoformat()
    message = {
        "id": str(uuid.uuid4()),
        "conversation_id": conversation_id,
        "sender_id": user["id"],
        "sender_name": user.get("full_name", ""),
        "text": text,
        "read_by": [user["id"]],
        "created_at": now,
    }
    await db.chat_messages.insert_one(message)
    
    # Update conversation
    preview = text[:80] + ("..." if len(text) > 80 else "")
    await db.chat_conversations.update_one(
        {"id": conversation_id},
        {"$set": {"last_message_at": now, "last_message_preview": preview, "last_message_sender": user.get("full_name", "")}}
    )
    
    message.pop("_id", None)
    return message


@api_router.get("/chat/unread-count")
async def get_chat_unread_count(user=Depends(get_current_user)):
    """Get total unread message count for badge."""
    user_id = user["id"]
    convo_ids = []
    async for c in db.chat_conversations.find({"participants": user_id}, {"id": 1, "_id": 0}):
        convo_ids.append(c["id"])
    
    if not convo_ids:
        return {"unread_count": 0}
    
    count = await db.chat_messages.count_documents({
        "conversation_id": {"$in": convo_ids},
        "sender_id": {"$ne": user_id},
        "read_by": {"$nin": [user_id]}
    })
    return {"unread_count": count}


@api_router.get("/chat/users")
async def get_chat_users(user=Depends(get_current_user)):
    """Get all users available for chat with online status."""
    users = await db.users.find(
        {"id": {"$ne": user["id"]}},
        {"_id": 0, "id": 1, "full_name": 1, "role": 1, "department": 1, "last_active": 1, "is_active": 1}
    ).sort("full_name", 1).to_list(500)
    
    now = datetime.now(timezone.utc)
    for u in users:
        la = u.get("last_active")
        if la:
            try:
                last = datetime.fromisoformat(la.replace("Z", "+00:00"))
                diff_minutes = (now - last).total_seconds() / 60
                u["status"] = "online" if diff_minutes < 10 else "away" if diff_minutes < 60 else "offline"
            except Exception:
                u["status"] = "offline"
        else:
            u["status"] = "offline"
    return users


@api_router.post("/chat/heartbeat")
async def chat_heartbeat(user=Depends(get_current_user)):
    """Update user's last_active timestamp."""
    await db.users.update_one({"id": user["id"]}, {"$set": {"last_active": datetime.now(timezone.utc).isoformat()}})
    return {"ok": True}


# ======================== EXECUTIVE DASHBOARD ========================

@api_router.get("/executive/dashboard")
async def get_executive_dashboard(user=Depends(get_current_user)):
    """CEO Executive Dashboard — merged operational + executive single-page overview."""
    if user["role"] not in ("super_admin", "admin"):
        raise HTTPException(403, "Executive dashboard is restricted")
    
    now = datetime.now(timezone.utc)
    current_month = now.strftime("%Y-%m")
    month_start = f"{current_month}-01"
    today = now.strftime("%Y-%m-%d")
    
    # Build proper 6-month ranges
    from calendar import monthrange
    trend_months = []
    for i in range(5, -1, -1):
        dt = (now.replace(day=1) - timedelta(days=i * 28)).replace(day=1)
        m = dt.strftime("%Y-%m")
        _, last_day = monthrange(dt.year, dt.month)
        m_start = f"{m}-01"
        m_end = f"{m}-{last_day}"
        trend_months.append({"month": m, "label": dt.strftime("%b %Y"), "start": m_start, "end": m_end})
    
    # === PARALLEL BATCH 1: Counts and aggregates ===
    (
        total_employees_count, total_leads_month, enrolled_month, new_leads_today,
        active_users, pending_approvals,
        employees_list, attendance_today_list, pending_leaves,
        revenue_data, cs_revenue_data, mentor_revenue_data,
        active_pipeline, pending_activations,
        rev_by_course_data, top_sales_data, top_cs_data, top_mentors_data,
        dept_count_data, lead_source_data,
        recent_enrollments_data, course_bifurcation_data,
        expiring_docs_raw, salary_payout_data, salary_fallback_data,
    ) = await asyncio.gather(
        db.hr_employees.count_documents({"employment_status": {"$in": ["active", "probation"]}}),
        db.leads.count_documents({"created_at": {"$gte": month_start}}),
        db.leads.count_documents({"stage": "enrolled", "enrolled_at": {"$gte": month_start}}),
        db.leads.count_documents({"created_at": {"$gte": today}}),
        db.users.count_documents({"is_active": True}),
        db.approval_requests.count_documents({"status": "pending"}),
        # Full employee list for gender + headcount
        db.hr_employees.find({"employment_status": {"$in": ["active", "probation"]}}, {"_id": 0, "id": 1, "gender": 1, "full_name": 1, "department": 1}).to_list(500),
        # Attendance today
        db.hr_attendance.find({"date": today}, {"_id": 0, "status": 1, "employee_id": 1}).to_list(500),
        # Pending leave requests
        db.hr_leave_requests.count_documents({"status": "pending"}),
        # Sales revenue this month
        db.leads.aggregate([
            {"$match": {"stage": "enrolled", "enrolled_at": {"$gte": month_start}}},
            {"$group": {"_id": None, "total": {"$sum": {"$ifNull": ["$enrollment_amount", {"$ifNull": ["$sale_amount", 0]}]}}, "count": {"$sum": 1}}}
        ]).to_list(1),
        # CS revenue this month
        db.cs_upgrades.aggregate([
            {"$match": {"created_at": {"$gte": month_start}}},
            {"$group": {"_id": None, "total": {"$sum": {"$ifNull": ["$amount", {"$ifNull": ["$upgrade_amount", 0]}]}}, "count": {"$sum": 1}}}
        ]).to_list(1),
        # Mentor/Academics revenue this month
        db.mentor_redeposits.aggregate([
            {"$match": {"date": {"$gte": month_start[:10]}}},
            {"$group": {"_id": None, "total": {"$sum": {"$ifNull": ["$amount_aed", {"$ifNull": ["$amount", 0]}]}}, "count": {"$sum": 1}}}
        ]).to_list(1),
        # Active pipeline
        db.leads.count_documents({"stage": {"$in": ["warm_lead", "hot_lead", "in_progress"]}}),
        # Pending activations
        db.students.count_documents({"status": {"$in": ["pending_activation", "pending"]}}),
        # Revenue by course (with proper course_name fallback)
        db.leads.aggregate([
            {"$match": {"stage": "enrolled", "enrolled_at": {"$gte": month_start}}},
            {"$addFields": {"display_course": {"$ifNull": ["$course_name", {"$ifNull": ["$interested_course_name", "Unknown Course"]}]}}},
            {"$group": {"_id": "$display_course", "total": {"$sum": {"$ifNull": ["$enrollment_amount", {"$ifNull": ["$sale_amount", 0]}]}}, "count": {"$sum": 1}}},
            {"$sort": {"total": -1}}, {"$limit": 10}
        ]).to_list(10),
        # Top sales agents
        db.leads.aggregate([
            {"$match": {"stage": "enrolled", "enrolled_at": {"$gte": month_start}}},
            {"$group": {"_id": "$assigned_to_name", "total": {"$sum": {"$ifNull": ["$enrollment_amount", {"$ifNull": ["$sale_amount", 0]}]}}, "count": {"$sum": 1}}},
            {"$sort": {"total": -1}}, {"$limit": 5}
        ]).to_list(5),
        # Top CS agents
        db.cs_upgrades.aggregate([
            {"$match": {"created_at": {"$gte": month_start}}},
            {"$group": {"_id": "$cs_agent_name", "total": {"$sum": {"$ifNull": ["$amount", {"$ifNull": ["$upgrade_amount", 0]}]}}, "count": {"$sum": 1}}},
            {"$sort": {"total": -1}}, {"$limit": 5}
        ]).to_list(5),
        # Top mentors
        db.mentor_redeposits.aggregate([
            {"$match": {"date": {"$gte": month_start[:10]}}},
            {"$group": {"_id": "$mentor_name", "total": {"$sum": {"$ifNull": ["$amount_aed", {"$ifNull": ["$amount", 0]}]}}, "count": {"$sum": 1}}},
            {"$sort": {"total": -1}}, {"$limit": 5}
        ]).to_list(5),
        # Department headcount
        db.hr_employees.aggregate([
            {"$match": {"employment_status": {"$in": ["active", "probation"]}}},
            {"$group": {"_id": "$department", "count": {"$sum": 1}}},
            {"$sort": {"count": -1}}
        ]).to_list(20),
        # Lead sources
        db.leads.aggregate([
            {"$match": {"created_at": {"$gte": month_start}}},
            {"$group": {"_id": "$lead_source", "count": {"$sum": 1}}},
            {"$sort": {"count": -1}}, {"$limit": 8}
        ]).to_list(8),
        # Recent enrollments
        db.leads.find({"stage": "enrolled"}, {"_id": 0, "full_name": 1, "sale_amount": 1, "enrollment_amount": 1, "enrolled_at": 1, "assigned_to_name": 1, "interested_course_name": 1, "course_name": 1}).sort("enrolled_at", -1).to_list(5),
        # Course bifurcation for new accounts this month
        db.leads.aggregate([
            {"$match": {"stage": "enrolled", "enrolled_at": {"$gte": month_start}}},
            {"$addFields": {"display_course": {"$ifNull": ["$course_name", {"$ifNull": ["$interested_course_name", "Unknown"]}]}}},
            {"$group": {"_id": "$display_course", "count": {"$sum": 1}}},
            {"$sort": {"count": -1}}
        ]).to_list(20),
        # Expiring documents in next 30 days
        db.hr_employees.find(
            {"employment_status": {"$in": ["active", "probation"]}},
            {"_id": 0, "id": 1, "full_name": 1, "department": 1, "passport_expiry": 1, "visa_expiry": 1, "emirates_id_expiry": 1, "labour_card_expiry": 1, "insurance_expiry": 1}
        ).to_list(500),
        # Total salary payout (from latest payroll batch or fallback to salary_structure)
        db.hr_payroll.aggregate([
            {"$match": {"month": current_month}},
            {"$group": {"_id": None, "total_gross": {"$sum": "$gross_salary"}, "total_net": {"$sum": "$net_salary"}, "total_deductions": {"$sum": "$total_deductions"}, "count": {"$sum": 1}}}
        ]).to_list(1),
        # Fallback: salary_structure totals
        db.hr_employees.aggregate([
            {"$match": {"employment_status": {"$in": ["active", "probation"]}}},
            {"$group": {"_id": None, "total_gross": {"$sum": {"$ifNull": ["$salary_structure.gross_salary", 0]}}, "count": {"$sum": 1}}}
        ]).to_list(1),
    )
    
    # === PARALLEL BATCH 2: Monthly revenue trend (3 collections x 6 months) ===
    trend_tasks = []
    for tm in trend_months:
        trend_tasks.append(db.leads.aggregate([
            {"$match": {"stage": "enrolled", "enrolled_at": {"$gte": tm["start"], "$lte": tm["end"]}}},
            {"$group": {"_id": None, "total": {"$sum": {"$ifNull": ["$enrollment_amount", {"$ifNull": ["$sale_amount", 0]}]}}}}
        ]).to_list(1))
        trend_tasks.append(db.cs_upgrades.aggregate([
            {"$match": {"created_at": {"$gte": tm["start"], "$lte": tm["end"]}}},
            {"$group": {"_id": None, "total": {"$sum": {"$ifNull": ["$amount", {"$ifNull": ["$upgrade_amount", 0]}]}}}}
        ]).to_list(1))
        trend_tasks.append(db.mentor_redeposits.aggregate([
            {"$match": {"date": {"$gte": tm["start"][:10], "$lte": tm["end"][:10]}}},
            {"$group": {"_id": None, "total": {"$sum": {"$ifNull": ["$amount_aed", {"$ifNull": ["$amount", 0]}]}}}}
        ]).to_list(1))
    trend_results = await asyncio.gather(*trend_tasks)
    
    # Process revenue values
    s_rev = (revenue_data[0] if revenue_data else {}).get("total", 0) or 0
    cs_rev = (cs_revenue_data[0] if cs_revenue_data else {}).get("total", 0) or 0
    m_rev = (mentor_revenue_data[0] if mentor_revenue_data else {}).get("total", 0) or 0
    total_rev = s_rev + cs_rev + m_rev
    
    # Build monthly trend with 3-department breakdown
    monthly_trend = []
    for i, tm in enumerate(trend_months):
        s_val = (trend_results[i*3][0] if trend_results[i*3] else {}).get("total", 0) or 0
        c_val = (trend_results[i*3+1][0] if trend_results[i*3+1] else {}).get("total", 0) or 0
        m_val = (trend_results[i*3+2][0] if trend_results[i*3+2] else {}).get("total", 0) or 0
        monthly_trend.append({
            "month": tm["month"], "label": tm["label"],
            "sales": round(s_val, 2), "cs": round(c_val, 2), "mentors": round(m_val, 2),
            "total": round(s_val + c_val + m_val, 2)
        })
    
    # Attendance breakdown for today
    present_count = sum(1 for a in attendance_today_list if a.get("status") in ["present", "late"])
    half_day_count = sum(1 for a in attendance_today_list if a.get("status") == "half_day")
    absent_count = sum(1 for a in attendance_today_list if a.get("status") == "absent")
    on_leave_count = sum(1 for a in attendance_today_list if a.get("status") == "on_leave")
    warning_count = sum(1 for a in attendance_today_list if a.get("status") == "warning")
    
    # Gender bifurcation - ensure proper tagging
    gender_breakdown = {"Male": 0, "Female": 0}
    for emp in employees_list:
        g = (emp.get("gender") or "").strip().lower()
        if g in ("male", "m"):
            gender_breakdown["Male"] += 1
        elif g in ("female", "f"):
            gender_breakdown["Female"] += 1
        else:
            gender_breakdown.setdefault("Other", 0)
            gender_breakdown["Other"] += 1
    # Remove "Other" if 0
    if gender_breakdown.get("Other", 0) == 0:
        gender_breakdown.pop("Other", None)
    
    # Commission approval status
    approvals = await db.commission_approvals.find({"month": current_month}, {"_id": 0}).to_list(10)
    commission_approvals = {a["department"]: a["status"] for a in approvals}
    
    # Process expiring documents (next 30 days)
    expiring_documents = []
    cutoff_date = (now + timedelta(days=30)).strftime("%Y-%m-%d")
    for emp in expiring_docs_raw:
        doc_types = [
            ("Passport", emp.get("passport_expiry")),
            ("Visa", emp.get("visa_expiry")),
            ("Emirates ID", emp.get("emirates_id_expiry")),
            ("Labour Card", emp.get("labour_card_expiry")),
            ("Insurance", emp.get("insurance_expiry")),
        ]
        for doc_name, expiry in doc_types:
            if expiry and expiry <= cutoff_date and expiry >= today:
                expiring_documents.append({
                    "employee": emp.get("full_name"), "department": emp.get("department"),
                    "document": doc_name, "expiry_date": expiry,
                    "days_left": (datetime.strptime(expiry, "%Y-%m-%d") - datetime.strptime(today, "%Y-%m-%d")).days
                })
    expiring_documents.sort(key=lambda x: x.get("days_left", 99))
    
    # Salary payout: prefer actual payroll data, fallback to salary_structure
    payout = salary_payout_data[0] if salary_payout_data else None
    if payout and payout.get("count", 0) > 0:
        total_salary_payout = payout.get("total_gross", 0) or 0
        total_net_payout = payout.get("total_net", 0) or 0
        payout_count = payout.get("count", 0)
        total_deductions = payout.get("total_deductions", 0) or 0
    else:
        fb = salary_fallback_data[0] if salary_fallback_data else {}
        total_salary_payout = fb.get("total_gross", 0) or 0
        total_net_payout = total_salary_payout
        payout_count = fb.get("count", 0)
        total_deductions = 0
    
    # Estimated total commission payout this month (from live commission calculations)
    total_commission_estimate = 0
    try:
        # Quick commission total — sum from sales+CS agents directly
        sales_agents = await db.users.find(
            {"role": {"$in": ["sales_executive", "team_leader"]}, "is_active": True},
            {"_id": 0, "id": 1}
        ).to_list(100)
        cs_agents = await db.users.find(
            {"role": {"$in": ["cs_agent", "cs_head"]}, "is_active": True},
            {"_id": 0, "id": 1, "full_name": 1}
        ).to_list(50)
        
        sales_tasks = [_calc_sales_commissions(a["id"], current_month) for a in sales_agents]
        cs_tasks = [_calc_cs_commissions(a["id"], a.get("full_name", ""), current_month) for a in cs_agents]
        all_comms = await asyncio.gather(*sales_tasks, *cs_tasks)
        
        sales_comms = all_comms[:len(sales_agents)]
        cs_comms = all_comms[len(sales_agents):]
        
        total_commission_estimate = round(
            sum(c.get("earned_commission", 0) + c.get("pending_commission", 0) for c in sales_comms) +
            sum(c.get("earned_tl", 0) + c.get("pending_tl", 0) for c in sales_comms if c.get("is_tl_or_sm")) +
            sum(c.get("earned_commission", 0) + c.get("pending_commission", 0) for c in cs_comms) +
            sum(c.get("earned_cs_head", 0) for c in cs_comms),
        2)
    except Exception as e:
        logger.warning(f"Failed to get commission totals for exec dash: {e}")
    
    # Revenue split by department
    revenue_split = [
        {"name": "Sales", "value": round(s_rev, 2)},
        {"name": "Customer Service", "value": round(cs_rev, 2)},
        {"name": "Academics", "value": round(m_rev, 2)},
    ]
    
    return {
        "kpis": {
            "total_employees": total_employees_count,
            "active_users": active_users,
            "new_leads_today": new_leads_today,
            "total_leads_month": total_leads_month,
            "enrolled_month": enrolled_month,
            "revenue_month": round(total_rev, 2),
            "sales_revenue": round(s_rev, 2),
            "cs_revenue": round(cs_rev, 2),
            "mentor_revenue": round(m_rev, 2),
            "cs_upgrades_month": (cs_revenue_data[0] if cs_revenue_data else {}).get("count", 0) or 0,
            "cs_upgrade_revenue": round(cs_rev, 2),
            "pending_approvals": pending_approvals,
            "pending_leaves": pending_leaves,
            "active_pipeline": active_pipeline,
            "pending_activations": pending_activations,
        },
        "attendance": {
            "present": present_count,
            "half_day": half_day_count,
            "absent": absent_count,
            "on_leave": on_leave_count,
            "warning": warning_count,
            "total": len(attendance_today_list) if attendance_today_list else total_employees_count,
        },
        "gender_breakdown": gender_breakdown,
        "monthly_trend": monthly_trend,
        "revenue_split": revenue_split,
        "revenue_by_course": [{"course": r["_id"] or "Unknown Course", "revenue": r.get("total", 0) or 0, "count": r.get("count", 0)} for r in rev_by_course_data],
        "top_performers": {
            "sales": [{"name": a["_id"] or "Unknown", "revenue": round(a.get("total", 0), 2), "deals": a.get("count", 0)} for a in top_sales_data],
            "cs": [{"name": a["_id"] or "Unknown", "revenue": round(a.get("total", 0), 2), "upgrades": a.get("count", 0)} for a in top_cs_data],
            "mentors": [{"name": a["_id"] or "Unknown", "revenue": round(a.get("total", 0), 2), "deposits": a.get("count", 0)} for a in top_mentors_data],
        },
        "department_headcount": [{"department": d["_id"] or "Unknown", "count": d["count"]} for d in dept_count_data],
        "lead_sources": [{"source": s["_id"] or "Unknown", "count": s["count"]} for s in lead_source_data],
        "recent_enrollments": [{"name": e.get("full_name"), "amount": e.get("enrollment_amount") or e.get("sale_amount", 0), "date": e.get("enrolled_at"), "agent": e.get("assigned_to_name"), "course": e.get("course_name") or e.get("interested_course_name")} for e in recent_enrollments_data],
        "course_bifurcation": [{"course": c["_id"] or "Unknown", "count": c["count"]} for c in course_bifurcation_data],
        "expiring_documents": expiring_documents[:10],
        "salary_payout": {
            "total_gross": round(total_salary_payout, 2),
            "total_net": round(total_net_payout, 2),
            "total_deductions": round(total_deductions, 2),
            "total_commission": total_commission_estimate,
            "total_payout": round(total_net_payout + total_commission_estimate, 2),
            "employee_count": payout_count,
        },
        "commission_approvals": commission_approvals,
        "current_month": current_month,
    }
# Include the router in the main app
app.include_router(api_router)

app.add_middleware(GZipMiddleware, minimum_size=500)

app.add_middleware(
    CORSMiddleware,
    allow_credentials=True,
    allow_origins=os.environ.get('CORS_ORIGINS', '*').split(','),
    allow_methods=["*"],
    allow_headers=["*"],
)

